// ── Daily Challenge Question Bank ────────────────────────────────────────────
// Scenario-based questions, separate from the topic question banks.
// The daily seeded shuffle picks 10 from this pool each day.

export const DAILY_QUESTIONS = {
  he: [
    // ── Workloads ──
    {q:"ה-Pod בשם api-server מציג סטטוס CrashLoopBackOff. מה הצעד הראשון לאבחון?",options:["kubectl delete pod api-server","kubectl logs api-server --previous","kubectl edit pod api-server","kubectl drain node"],answer:1,explanation:"-previous מציג לוגים מהריצה שקרסה.\nזה תמיד הצעד הראשון כשיש CrashLoopBackOff. הלוגים יחשפו את שגיאת האתחול."},
    {q:"ה-Pod נשאר Pending. kubectl describe מציג: '0/3 nodes available: 3 Insufficient memory'. מה הפתרון הנכון?",options:["הפעלת ה-Pod מחדש ובדיקת הסטטוס","העברת ה-Pod ל-namespace עם פחות עומס","הורדת memory requests של ה-Pod או הוספת Node","מחיקת Pods אחרים כדי לפנות זיכרון"],answer:2,explanation:"ה-Scheduler לא מוצא Node עם זיכרון פנוי שיכסה את ה-requests.\nיש להוריד את דרישות הזיכרון של ה-Pod או להוסיף Node לאשכול."},
    {q:"תהליך Rolling update של Deployment נתקע. Pod חדש נוצר אבל לא עולה ל-Ready. מה הסיבה הנפוצה ביותר?",options:["image לא קיים ב-repo","readiness probe נכשלת על ה-Pod החדש","resource limits גורמים ל-OOMKill של ה-Pod החדש","maxUnavailable מוגדר ל-0 וה-Pod הישן תקוע"],answer:1,explanation:"כשrollout נתקע, הסיבה הנפוצה ביותר היא readiness probe כושלת. Kubernetes מחכה ל-Pod להיות Ready לפני שממשיך לעדכן Pods נוספים."},
    {q:"ה-Pod קרס עם OOMKilled. מה המשמעות ומה הצעד הבא?",options:["בעיית רשת. בודקים NetworkPolicy ו-DNS","הקרנל סיים את הקונטיינר כי חרג מ-memory limit. מגדילים limits.memory","image פגום. מושכים מחדש ועושים restart","CPU throttling גורם ל-timeout. מגדילים CPU limits"],answer:1,explanation:"OOMKilled = Out Of Memory Killed.\nהקרנל הרג את הקונטיינר מאחר חרג ממגבלת הזיכרון.\nיש להגדיל את limits.memory או לאתר memory leak באפליקציה."},
    {q:"ה-HPA מוגדר ל-Deployment, אך לא מבצע scale למרות עומס CPU גבוה. מה הסיבה הסבירה ביותר?",options:["ה-Deployment כבר הגיע ל-maxReplicas","metrics-server לא מותקן או לא עובד","ה-HPA מוגדר על metric שגוי (memory במקום CPU)","ה-Pod מגדיר CPU limits אבל לא requests"],answer:1,explanation:"HPA תלוי ב-metrics-server כדי לקרוא נתוני CPU/memory.\nללא metrics-server, ה-HPA לא יכול לקבל מדדים ולכן לא מבצע scaling."},
    {q:"ה-Init Container נכשל בכל ניסיון עם exit code 1. ה-Logs מציגים 'connection refused'. מה בודקים?",options:["DNS resolution של השירות היעד נכשלת","האם השירות שה-init container מחכה לו בכלל פעיל","image tag שגוי של ה-init container","ה-init container חסר network access בגלל NetworkPolicy"],answer:1,explanation:"Init containers משמשים לרוב להמתנה לשירות חיצוני. connection refused אומר שהיעד לא זמין.\nיש לוודא שה-dependency כבר רץ ופועל."},
    {q:"ה-Deployment מנסה להריץ 5 replicas אך רק 3 עולים. kubectl describe מציג 'pod didn't trigger scale-up'. מה בודקים?",options:["cluster autoscaler לא מוגדר או Nodes לא יכולים להתרחב","ה-image לא נמצא ב-registry וה-Pods נכשלים ב-pull","ResourceQuota ב-namespace מגביל את מספר ה-Pods","PodDisruptionBudget מונע יצירת replicas נוספים"],answer:0,explanation:"כש-Pods לא יכולים להיות scheduled, Cluster Autoscaler אמור להוסיף Nodes.\nאם זה לא קורה, ייתכן שאין תצורת autoscaling, ה-quota ממלאה, או שאין cloud instances זמינות."},
    {q:"ה-Job רץ אך לעולם לא מסתיים. kubectl get job מציג COMPLETIONS 0/1 כבר שעה. מה בודקים?",options:["מחיקת ה-Job ויצירה מחדש","kubectl logs של Pod ה-Job. ייתכן שהתהליך תקוע","kubectl describe node","שינוי restartPolicy"],answer:1,explanation:"Job שלא מסתיים בד\"כ תקוע בתהליך שלא יוצא. יש לראות לוגים של ה-Pod כדי להבין אם זה deadlock, קלט חסר, או תהליך אינסופי."},
    {q:"ה-Pod מציג READY 0/1 אך STATUS Running. האפליקציה בפנים עובדת. מה הבעיה?",options:["liveness probe נכשלת וה-Pod עומד לקרוס","readiness probe נכשלת, ה-Pod לא מקבל traffic","ה-Pod עדיין באתחול ולא סיים startup","ה-Service selector לא תואם את labels של ה-Pod"],answer:1,explanation:"0/1 Ready אומר ש-readiness probe נכשלת.\nה-Pod רץ אבל לא יקבל traffic מה-Service.\nיש לבדוק את הגדרת ה-readiness probe ולוודא שה-Path וה-Port נכונים."},
    {q:"ה-StatefulSet database-0 קרס ולא עולה מחדש. kubectl describe מציג 'volume is already exclusively attached'. מה קרה?",options:["ה-PVC נמחק ויש ליצור אותו מחדש","ה-PVC עם ReadWriteOnce מחובר ל-Node אחר. Node drain לא הושלם","ה-StorageClass לא תומך ב-StatefulSet","ה-volume הגיע לגבול הנפח ויש להרחיב את ה-PVC"],answer:1,explanation:"ReadWriteOnce מאפשר חיבור ל-Node אחד בלבד.\nאם ה-Node הקודם לא שחרר את ה-volume לחלוטין (למשל לאחר crash), ה-Pod החדש לא יכול לחבר אותו.\nפתרון: לחכות ל-Node detach או לאלץ detach."},

    // ── Networking ──
    {q:"הפקודה kubectl get endpoints my-svc מציג '<none>'. Service קיים, Pods רצים. מה הבעיה?",options:["ה-Pods לא עברו readiness check ולכן לא נרשמו כ-endpoints","selector של Service לא תואם labels של Pods","ה-Pods רצים ב-namespace אחר מה-Service","ה-Service מוגדר כ-ExternalName ולא מפנה ל-Pods"],answer:1,explanation:"כש-Endpoints ריק, זה כמעט תמיד חוסר התאמה בין selector של ה-Service לבין labels של ה-Pods.\nבודקים עם kubectl get pods --show-labels."},
    {q:"ה-Pod לא מצליח לפנות לשירות אחר באשכול. curl http://my-svc.default.svc.cluster.local מחזיר 'Could not resolve host'. מה בודקים?",options:["בדיקת resolv.conf בתוך ה-Pod לוודא שה-DNS server נכון","CoreDNS Pods ב-kube-system. האם הם רצים ובריאים?","בדיקת Service שקיים ושהשם תואם","בדיקת /etc/hosts בתוך ה-Pod"],answer:1,explanation:"שגיאת DNS בתוך האשכול מצביעה על CoreDNS.\nיש לבדוק: kubectl get pods -n kube-system | grep coredns ולוודא שהם Running ו-Ready."},
    {q:"ה-Ingress מוגדר, DNS מצביע נכון, אך כל הבקשות מחזירות 404. מה בודקים?",options:["TLS cert","path ב-Ingress rule לא תואם ל-path שהאפליקציה מאזינה לו","namespace של Ingress","image של Pod"],answer:1,explanation:"404 מ-Ingress בד\"כ אומר שה-path rule לא תואם. אם האפליקציה מאזינה על / אבל ה-Ingress מגדיר path: /api, הנתיב לא יתאים. יש לבדוק path ו-pathType."},
    {q:"כלל ה-NetworkPolicy הוחלה על namespace. עכשיו Pod A לא יכול לדבר עם Pod B באותו namespace. מה קרה?",options:["NetworkPolicy ב-K8s default-deny, לא הוגדרה allow rule בין ה-Pods","ה-NetworkPolicy חלה רק על Pod A אבל לא על Pod B","ה-CNI plugin לא תומך ב-NetworkPolicy ולכן היא לא נאכפת","ה-Pods משתמשים ב-hostNetwork ו-NetworkPolicy לא חלה עליהם"],answer:0,explanation:"NetworkPolicy ב-Kubernetes היא additive allow-list.\nכשמחילים policy, כל traffic שלא מוגדר במפורש כ-allow נחסם.\nיש להוסיף ingress rule שמאפשרת תקשורת בתוך ה-namespace."},
    {q:"ה-Service מסוג LoadBalancer נשאר בסטטוס Pending (EXTERNAL-IP <pending>) ב-single-node local cluster. מה הסיבה?",options:["ה-Service מפנה ל-port שגוי וה-cloud provider לא מקצה IP","LoadBalancer דורש cloud provider. ב-local cluster אין תמיכה ללא MetalLB","ה-Node לא מחובר לרשת חיצונית ולכן לא ניתן להקצות IP","ה-selector של ה-Service לא תואם Pods וה-IP לא מוקצה"],answer:1,explanation:"ServiceType LoadBalancer מסתמך על cloud provider (AWS, GCP, Azure) שיקצה IP חיצוני.\nב-local cluster (minikube, kind) זה לא זמין ללא כלים כמו MetalLB.\nלשימוש local משתמשים ב-NodePort."},
    {q:"ה-Pod לא יכול לגשת לאינטרנט. curl google.com נכשל, אבל Pod אחר באותו namespace כן מצליח. מה בודקים?",options:["בדיקת resolv.conf של ה-Pod לוודא DNS תקין","NetworkPolicy על ה-Pod הספציפי שחוסמת egress","בדיקת routing table של ה-Node שה-Pod רץ עליו","ה-Pod משתמש ב-ServiceAccount עם הגבלות רשת"],answer:1,explanation:"אם Pod אחד לא יכול לגשת לחוץ אבל אחרים כן, NetworkPolicy egress היא החשודה הראשית.\nיש לבדוק policies שחלות על ה-Pod לפי labels."},
    {q:"ה-Service ClusterIP נגיש מתוך ה-Pods, אך NodePort על port 30080 לא נגיש מחוץ לאשכול. מה הסיבה האפשרית?",options:["firewall/security group חוסמים port 30080","ה-Node לא מאזין על port 30080 כי kube-proxy לא פעיל","ה-Service מוגדר עם externalTrafficPolicy: Local ואין Pod על ה-Node","ה-NodePort port מחוץ לטווח המותר (30000-32767)"],answer:0,explanation:"NodePort פותח port על כל ה-Nodes, אך firewall חיצוני (security groups, iptables) עלול לחסום אותו.\nיש לוודא ש-port 30080 פתוח ב-security group ושאין iptables rule שחוסמת."},

    // ── Config & Security ──
    {q:"ה-Pod לא מצליח לפנות ל-Secrets שיצרת. kubectl describe pod מציג 'secret not found'. מה בודקים?",options:["שם ה-Secret ב-Pod spec שונה מהשם שנוצר","האם ה-Secret נמצא באותו namespace כמו ה-Pod","ה-Secret נוצר כ-type Opaque במקום type הנדרש","ה-Secret ריק ולכן K8s מתעלם ממנו"],answer:1,explanation:"Secrets ו-Pods חייבים להיות באותו namespace.\nSecret ב-namespace A לא נגיש ל-Pod ב-namespace B.\nיש לוודא שה-Secret נוצר ב-namespace הנכון."},
    {q:"ה-ServiceAccount של Pod מנסה לבצע kubectl get pods ומקבל 'Forbidden'. Role קיים. מה חסר?",options:["הגדלת resource limits","RoleBinding שמחבר את ה-Role ל-ServiceAccount","ClusterRole","Secret"],answer:1,explanation:"Role לבד לא מספיקה.\nיש צורך ב-RoleBinding שמחבר בין ה-Role (הרשאות) לבין ה-Subject (ServiceAccount).\nללא RoleBinding, ה-Role לא תקפה."},
    {q:"ה-ConfigMap עודכן עם ערכים חדשים, אך האפליקציה ב-Pod עדיין רואה ערכים ישנים. למה?",options:["ConfigMap לא תקין ויש לאמת את הפורמט","רוב האפליקציות טוענות ConfigMap פעם אחת בהפעלה, Pod צריך restart","kubelet לא סינכרן את ה-ConfigMap ויש לחכות כמה דקות","ה-ConfigMap הוגדר כ-immutable ולכן העדכון לא נשמר"],answer:1,explanation:"כש-ConfigMap מוגדר כ-env vars, השינויים יכנסו לתוקף רק אחרי restart של ה-Pod.\nאם מוגדר כ-volume, עדכון יכול להגיע בתוך כמה דקות, אבל האפליקציה עצמה צריכה לקרוא מחדש."},
    {q:"ה-Pod מנסה לפנות ל-private Docker registry ומקבל 'ImagePullBackOff'. מה חסר?",options:["ה-image tag שצוין לא קיים ב-registry","imagePullSecrets לא מוגדר ב-Pod spec. חסר credentials ל-registry","ה-Pod רץ על Node ללא גישת רשת ל-registry","ה-ServiceAccount של ה-Pod חסר הרשאות pull"],answer:1,explanation:"כדי למשוך image מ-private registry, ה-Pod צריך imagePullSecrets שמפנה ל-Secret מסוג kubernetes.io/dockerconfigjson עם credentials של ה-registry."},
    {q:"ה-Pod מנסה לרוץ כ-root (uid 0) אבל נדחה. מה הסיבה הסבירה?",options:["ה-Node מוגדר עם seccomp profile שחוסם root","PodSecurityAdmission או PodSecurityPolicy מגדיר runAsNonRoot: true","ה-image מוגדר עם USER root וזה גורם לשגיאה","ה-container runtime מונע הרצה כ-root כברירת מחדל"],answer:1,explanation:"PodSecurity admission control יכול לאסור הרצה כ-root.\nאם namespace מוגדר עם policy restricted או baseline, Pods שמנסים לרוץ כ-root יידחו.\nיש לשנות securityContext.runAsUser."},
    {q:"ה-Secret מוגדר ב-Pod כ-env var: value = 'dXNlcjpwYXNz'. האפליקציה מקבלת את הסטרינג הזה, לא את 'user:pass'. מה הבעיה?",options:["ה-Secret נוצר עם type: Opaque במקום kubernetes.io/basic-auth","ה-Secret נוצר עם ערך שכבר encoded ב-base64, ו-K8s פענח רק שכבה אחת","ה-Pod קורא את ה-Secret כ-volume file במקום env var","ה-Secret הוגדר עם stringData אך K8s שמר אותו כ-data ללא המרה"],answer:1,explanation:"K8s מפענח Secret מ-base64 אוטומטית כשמזריק ל-Pod.\nאם נוצר Secret עם ערך שכבר base64 encoded, ה-Pod יקבל base64 במקום הערך האמיתי.\nיש ליצור Secret עם הערך הגולמי."},

    // ── Storage ──
    {q:"ה-PVC בסטטוס Pending. kubectl describe pvc מציג 'storageclass.storage.k8s.io not found'. מה הבעיה?",options:["ה-PVC מבקש נפח גדול מדי ואין PV שתואם","StorageClass שצוין ב-PVC לא קיים באשכול. בדוק עם kubectl get storageclass","ה-PVC הוגדר ללא accessMode ולכן לא ניתן לבצע binding","ה-default StorageClass מוגדר אך אין provisioner פעיל"],answer:1,explanation:"PVC מפנה ל-StorageClass שלא קיים.\nיש לוודא ששם ה-StorageClass ב-PVC תואם לאחד מה-StorageClasses הקיימים (kubectl get storageclass)."},
    {q:"שני Pods מנסים לחבר אותו PVC. ה-Pod השני נשאר Pending עם 'Multi-Attach error'. מה הסיבה?",options:["ה-PV הגיע לנפח מלא ולא ניתן לחבר Pod נוסף","PVC עם accessMode ReadWriteOnce (RWO) יכול להיות מחובר ל-Node אחד בלבד","ה-StorageClass לא תומך ב-multi-attach וצריך להחליף provider","ה-Pod השני רץ על אותו Node אבל חסר mount path"],answer:1,explanation:"ReadWriteOnce אומר שהvolume יכול להיות mounted ל-Node אחד בלבד בכל זמן נתון.\nאם שני Pods על Nodes שונים מנסים לחבר, ה-Pod השני נחסם.\nפתרון: שינוי ל-ReadWriteMany אם ה-storage backend תומך."},
    {q:"פקודת Helm upgrade נכשל עם 'cannot patch because a resource with that name already exists (not managed by Helm)'. מה קרה?",options:["ה-chart version לא תואם ל-release הקיים ויש לבצע helm rollback","משאב נוצר ידנית מחוץ ל-Helm ולכן Helm לא מנהל אותו","release קודם לא נמחק לחלוטין ויש לבצע helm uninstall קודם","ה-values.yaml מכיל שדות שמתנגשים עם ברירות מחדל של ה-chart"],answer:1,explanation:"Helm עוקב אחרי משאבים שהוא יצר.\nאם משאב נוצר ידנית עם אותו שם, Helm לא יכול לנהל אותו.\nאפשר להשתמש ב-kubectl annotate לסמן אותו כ-managed by Helm, או למחוק ולאפשר ל-Helm ליצור מחדש."},
    {q:"ה-PV נמחק בזמן ש-PVC עדיין קיים. PVC עכשיו בסטטוס 'Lost'. מה עושים?",options:["מוחקים את ה-PVC ויוצרים PVC חדש עם PV חדש","יוצרים PV חדש עם claimRef שמצביע על ה-PVC הקיים","ממתינים עד שה-PVC יעבור אוטומטית לסטטוס Available","עורכים את ה-PVC ומסירים את ההפניה ל-PV שנמחק"],answer:1,explanation:"כש-PV נמחק, ה-PVC עובר לסטטוס Lost.\nיש ליצור PV חדש עם spec.claimRef שמצביע על ה-namespace ושם של ה-PVC הקיים, כך ה-binding יוחזר."},
    {q:"ה-Pod מנסה לכתוב ל-volume אך מקבל 'Read-only file system'. PVC מוגדר ב-YAML. מה בודקים?",options:["ה-PV mounted כ-read-only ברמת ה-StorageClass","volumeMounts.readOnly: true מוגדר ב-Pod spec. יש להסיר","ה-container רץ כ-non-root ואין הרשאות כתיבה על ה-directory","ה-filesystem של ה-PV מלא ולכן מערכת ההפעלה חסמה כתיבה"],answer:1,explanation:"אם volumeMounts מוגדר עם readOnly: true, ה-container לא יכול לכתוב ל-volume גם אם ה-PVC מרשה זאת.\nיש להסיר readOnly: true מה-volumeMounts."},

    // ── Troubleshooting ──
    {q:"ה-Node עבר לסטטוס NotReady פתאום. מה הצעד הראשון לאבחון?",options:["בדיקת events עם kubectl get events ו-node conditions","kubectl describe node ו-ssh ל-Node לבדוק kubelet logs","בדיקה האם ה-Node חוזר מעצמו תוך כמה דקות","cordon של ה-Node למנוע scheduling חדש"],answer:1,explanation:"kubectl describe node יציג conditions ולחלץ מידע על הסיבה (DiskPressure, MemoryPressure, NetworkUnavailable).\nלאחר מכן SSH ל-Node ובדיקת: systemctl status kubelet."},
    {q:"ה-Pod תקוע בסטטוס Terminating כבר 30 דקות. kubectl delete לא עוזר. מה עושים?",options:["chmod על ה-Pod","kubectl delete pod <name> --force --grace-period=0","kubectl restart pod","חיכוי של שעה"],answer:1,explanation:"Pod שתקוע ב-Terminating בד\"כ חכה ל-finalizer שלא הסתיים. --force --grace-period=0 מאלץ מחיקה מיידית. יש להשתמש בזהירות ב-production."},
    {q:"הפקודה kubectl exec לא עובד על Pod. מקבל 'error: unable to upgrade connection: container not found'. מה הסיבה?",options:["ה-Pod מריץ כמה containers ויש לציין --container","ה-container כבר נסגר. Pod אולי ב-CrashLoop","kubelet על ה-Node לא מצליח להתחבר ל-container runtime","ה-Pod נמצא ב-Terminating ול-container אין PID פעיל"],answer:1,explanation:"kubectl exec פותח connection ל-container רץ.\nאם ה-container נסגר (CrashLoop), אין container שניתן ל-exec אליו.\nיש לבדוק logs ולתקן את הגורם לקריסה."},
    {q:"ה-Cluster Autoscaler לא מוסיף Nodes למרות Pods ב-Pending. מה בודקים?",options:["בדיקת events של ה-Pending Pods עם kubectl describe pod","לוגים של cluster-autoscaler Pod: ייתכן taint mismatch, quota, או instance type לא זמין","בדיקת Node capacity עם kubectl describe node ומציאת bottleneck","בדיקת cloud provider quota ומגבלות region"],answer:1,explanation:"ה-Autoscaler מוסיף Nodes רק אם הוא מזהה ש-Pods יכולים לרוץ על Node חדש.\nאם יש taint שאין ל-Pod toleration עבורו, quota שהתמלאה, או בעיה ב-cloud provider, הוא לא יוסיף."},
    {q:"ה-Node מציג DiskPressure. Pods מתחילים להיות evicted. מה הפתרון המהיר?",options:["הוספת Node חדש לאשכול כדי לפזר את העומס","ניקוי images, logs וקבצים זמניים ב-Node: docker system prune","הגדלת ephemeral-storage limits של ה-Pods","הפעלת log rotation ב-kubelet configuration"],answer:1,explanation:"DiskPressure מתרחש כשדיסק ה-Node מתמלא.\nהפתרון המהיר: SSH ל-Node, ניקוי images לא בשימוש (docker/crictl image prune) ולוגים ישנים.\nלטווח ארוך: הגדלת דיסק או שימוש ב-log rotation."},
    {q:"הפקודה kubectl top nodes נכשלת: 'error: Metrics API not available'. מה חסר?",options:["ה-kubelet לא מדווח metrics ויש לבדוק את הגדרותיו","metrics-server לא מותקן באשכול","ה-API server לא מוגדר עם aggregation layer","ה-Nodes לא חושפים את port 10250 ל-metrics-server"],answer:1,explanation:"kubectl top דורש את metrics-server שמספק CPU/memory metrics.\nללא זה, גם HPA לא יעבוד.\nמתקינים: kubectl apply -f https://github.com/kubernetes-sigs/metrics-server/releases/latest/download/components.yaml"},
    {q:"הפקודה kubectl drain node1 נחסם: 'cannot delete Pods not managed by ReplicationController, ReplicaSet, Job, DaemonSet, or StatefulSet'. מה עושים?",options:["kubectl delete node","מוסיפים --force --ignore-daemonsets","kubectl uncordon","יצירת PDB"],answer:1,explanation:"kubectl drain נחסם כש-Pods standalone (ללא controller) קיימים על ה-Node. -force מאפשר למחוק אותם. -ignore-daemonsets מתעלם מ-DaemonSet Pods שלא ניתן להזיז."},
    {q:"בדיקת Liveness probe מוגדר על path /healthz ומכשילה כל 30 שניות. ה-Container מופעל מחדש כל פעם. האפליקציה עובדת. מה בודקים?",options:["initialDelaySeconds קצר מדי והאפליקציה לא מספיקה לעלות","ה-liveness probe מגיעה ל-endpoint שגוי (port/path) או שהתגובה לא 200","timeoutSeconds קצר מדי וה-probe עושה timeout לפני תשובה","ה-container לא מספיק מהיר להגיב ל-probe בזמן"],answer:1,explanation:"אם האפליקציה עובדת אבל liveness probe מכשילה, כנראה שה-probe מוגדרת עם port או path שגוי, או שה-endpoint מחזיר status code שאינו 200-399.\nיש לוודא שהpath והport תואמים את ה-health endpoint של האפליקציה."},
    {q:"אחרי kubectl rollout undo, ה-Deployment חזר לגרסה קודמת אבל האפליקציה עדיין שבורה. מה בודקים?",options:["ה-Deployment עדיין בתהליך rollout ויש לחכות","ייתכן ש-undo חזר ל-revision שגם הוא שבור. בודקים rollout history ובוחרים revision ספציפי","ה-ConfigMap או Secrets שה-revision הקודם השתמש בהם השתנו","ה-Pod החדש עלה אבל readiness probe עדיין נכשלת"],answer:1,explanation:"kubectl rollout undo חוזר ל-revision הקודם, אבל אם גם הוא היה שבור, זה לא יעזור. kubectl rollout history deployment/my-app מציג את כל ה-revisions, ואפשר לחזור ל-revision ספציפי עם --to-revision=N."},
    {q:"הפקודה kubectl apply -f manifest.yaml עובד בלי שגיאות, אבל המשאב לא נוצר. מה בודקים?",options:["ה-API server קיבל את הבקשה אבל admission webhook דחה אותה","המשאב נוצר ב-namespace אחר. בודקים events ו-kubectl get בכל namespaces","ה-YAML מכיל apiVersion ישן וה-resource נוצר עם schema שונה","ה-YAML ריק או שה-kind לא מוכר ל-API server"],answer:1,explanation:"apply מצליח מבחינת API server, אבל ה-resource נוצר ב-namespace הגדרת ב-YAML (שאולי שגוי) או ב-default.\nיש לבדוק kubectl get <resource> --all-namespaces."},
    {q:"ה-Pod חדש לא יכול להיות scheduled על אף Node. kubectl describe pod מציג Taints. מה הפתרון?",options:["הסרת ה-taint מה-Nodes עם kubectl taint nodes","הוספת toleration ל-Pod spec שתואמת ל-taint של ה-Nodes","הוספת nodeSelector ל-Pod שמפנה ל-Node ספציפי","הגדלת resource requests כדי שה-scheduler ימצא Node מתאים"],answer:1,explanation:"כש-Node מסומן עם taint, רק Pods שיש להם toleration מתאים יוכלו לרוץ עליו.\nיש להוסיף ב-Pod spec תחת tolerations: ערך שתואם ל-taint (key, operator, effect)."},
    {q:"ה-etcd Pod ב-kube-system מציג בעיות. כמה etcd members יש לאשכול בריא ב-production?",options:["1","2","3 (או מספר אי-זוגי)","5 בהכרח"],answer:2,explanation:"etcd דורש quorum: רוב החברים חייבים להיות זמינים. 3 members מאפשרים כשל של 1. 5 מאפשרים כשל של 2.\nתמיד מספר אי-זוגי כדי למנוע split-brain.\nל-production נהוג 3 או 5."},
    {q:"ה-Namespace נמחק אבל תקוע בסטטוס Terminating. kubectl get namespace מציג Terminating כבר שעה. מה הסיבה?",options:["ה-API server לא הצליח לעדכן את ה-resource","יש finalizers על resources בתוך ה-namespace שמונעים מחיקה","ה-Node שמריץ workloads ב-namespace לא זמין","ה-namespace controller דורש restart ידני"],answer:1,explanation:"Namespace ב-Terminating בד\"כ תקוע בגלל finalizers שלא הוסרו. יש לזהות את ה-resources עם finalizers (בד\"כ CRDs) ולהסיר אותם ידנית. ניתן לערוך ה-namespace ולמחוק finalizers מה-spec."},
    {q:"ה-Pod רץ על Node1. kubectl drain node1 בוצע. אחרי כמה זמן ה-Pod עובר ל-Node אחר?",options:["מיידית. Kubernetes מזיז את ה-Pod החי ל-Node אחר","drain מסיים את ה-Pod, וה-controller (Deployment) יוצר Pod חדש על Node אחר","ה-Pod נשאר על ה-Node עד שה-cordon מוסר","ה-Scheduler מחכה ל-cooldown period של 5 דקות"],answer:1,explanation:"kubectl drain מסיים (terminates) את ה-Pod על ה-Node.\nה-Deployment controller, שמבחין שחסר replica, יצור Pod חדש שה-Scheduler ישים על Node אחר (שאינו cordoned)."},
    {q:"מערכת RBAC מוגדרת עם ClusterRole אבל ב-namespace ספציפי. איזה binding משתמשים?",options:["ClusterRoleBinding בלבד","RoleBinding: מאפשר שימוש ב-ClusterRole אבל רק ב-namespace של ה-RoleBinding","Role חדש עם אותם permissions ב-namespace","ServiceAccount token עם ClusterRole embedded"],answer:1,explanation:"RoleBinding יכול להתייחס ל-ClusterRole, אבל מגביל את ההרשאות ל-namespace של ה-RoleBinding עצמו.\nClusterRoleBinding יתן הרשאות על כל האשכול.\nל-scoped access: משתמשים ב-RoleBinding עם ref ל-ClusterRole."},
    {q:"ה-Pod ב-namespace prod מנסה לקבל ConfigMap מ-namespace staging. מה קורה?",options:["זה עובד אוטומטית בין namespaces","Pods לא יכולים לגשת ישירות ל-resources ב-namespaces אחרים","זה עובד רק אם שני ה-namespaces באותו Node","צריך ליצור ResourceQuota שמתירה גישה חוצת namespaces"],answer:1,explanation:"Pods ניגשים ל-ConfigMaps, Secrets, ו-resources אחרים רק בתוך ה-namespace שלהם.\nכדי לשתף data בין namespaces, יוצרים עותק בכל namespace או משתמשים ב-external config store."},
    {q:"שדה readinessGate מוגדר על Pod. Pod מציג READY 0/1 למרות ש-readiness probe מצליחה. מה בודקים?",options:["liveness probe כושלת וגורמת ל-restart לפני שה-Pod נהיה Ready","readinessGate condition חיצוני (כגון load balancer sync) לא נענה","ה-container עדיין ב-phase של image pull","ה-Service selector לא תואם ולכן ה-Pod לא נרשם כ-Ready"],answer:1,explanation:"readinessGates מאפשרים לגורמים חיצוניים ל-K8s לקבוע readiness.\nPod יהיה Ready רק אחרי שה-condition הנוסף (למשל network load balancer sync) מוגדר כ-True ב-status.\nיש לבדוק את ה-custom conditions."},
    {q:"נתת kubectl apply על PodDisruptionBudget. drain של Node נכשל: 'Cannot evict pod as it would violate the pod's disruption budget'. מה קרה?",options:["ה-Node כבר cordoned ולכן drain לא יכול לפעול שנית","PDB מגדיר minAvailable=2 אך יש רק 2 Pods, ולכן drain יוריד מתחת ל-minimum","ה-Pod משתמש ב-local PV שלא ניתן להעביר","ה-Deployment מוגדר עם maxUnavailable=0"],answer:1,explanation:"PDB מגדיר כמה Pods חייבים להישאר זמינים.\nאם drain ינסה למחוק Pod שיוריד את הכמות מתחת ל-minAvailable, הוא יחסום.\nהפתרון: לוודא שיש replicas מספיקות לפני drain, או להגדיל את ה-Deployment."},
    {q:"ב-debug של אפליקציה, מריצים kubectl exec pod -- env ורואים שמשתנה SECRET_KEY לא קיים. מה בודקים?",options:["ה-Pod לא קיבל ServiceAccount עם הרשאות לקרוא Secrets","ה-Secret לא קיים ב-namespace, או ש-secretKeyRef ב-YAML שגוי","ה-Secret מוצפן ולכן env vars לא נחשפים ישירות","צריך restart ל-Pod אחרי יצירת ה-Secret"],answer:1,explanation:"כשenv var מ-Secret חסר, הסיבות האפשריות: ה-Secret לא קיים, secretName שגוי, key שגוי, או namespace שגוי. kubectl get secret <name> -n <namespace> ו-kubectl describe pod לבדיקת status."},
    {q:"ה-Pod A מנסה לגשת ל-Pod B ב-port 8080. מקבל connection refused. NetworkPolicy לא מוגדרת. מה בודקים?",options:["ה-Pod B לא מאזין על port 8080. ייתכן שה-process לא עלה או מאזין על port אחר","ה-kube-proxy לא מעדכן את iptables rules כראוי","ה-Pods נמצאים על Nodes שונים ואין CNI מוגדר","ה-Service של Pod B לא כולל את port 8080 ב-spec"],answer:0,explanation:"ללא NetworkPolicy, traffic אינו נחסם ברמת הרשת.\nconnection refused אומר שאין process שמאזין על ה-port.\nבודקים: kubectl exec podB -- ss -tlnp."},
    {q:"ה-Deployment עם 3 replicas. כל ה-Pods מציגים ImagePullBackOff. kubectl describe מציג 'Back-off pulling image'. מה הצעד הראשון?",options:["בדיקת Node resources: ייתכן שאין מספיק disk למשוך images","בדיקת image tag ב-YAML: האם ה-tag קיים ב-registry","restart ל-kubelet על כל Nodes","בדיקה שה-imagePullPolicy מוגדר ל-Always"],answer:1,explanation:"ImagePullBackOff אומר שלא ניתן למשוך את ה-image.\nהסיבות הנפוצות: tag לא קיים, שם image שגוי, או חוסר ב-imagePullSecrets ל-private registry. kubectl describe pod יציג את ה-image name המדויק."},
    {q:"אשכול Kubernetes גדול. נרצה לוודא ש-Pods ייפרסו על Nodes ב-zones שונות ל-HA. איך עושים זאת?",options:["node affinity עם zone labels","topologySpreadConstraints עם topologyKey: topology.kubernetes.io/zone","pod anti-affinity עם topologyKey: topology.kubernetes.io/zone","הגדרת replicas שווה למספר ה-zones"],answer:1,explanation:"topologySpreadConstraints מאפשרים הגדרה ש-Pods יתפזרו באופן שווה על פני zones (או nodes, racks).\nמגדירים maxSkew ו-topologyKey ל-zone.\nזה עדיף על anti-affinity כי הוא גמיש ומדרגי יותר."},
    {q:"ה-Pod ב-CrashLoop. הלוגים מציגים permission denied על path /data. מה הבעיה?",options:["ה-volume לא חובר כראוי ל-/data","ה-container רץ כ-user ללא הרשאות write. בודקים securityContext ו-fsGroup","ה-image חסר את התיקייה /data ב-filesystem","ה-PVC מוגדר כ-ReadOnlyMany"],answer:1,explanation:"כשprocess בתוך container מנסה לכתוב ל-path שלו אין הרשאות, נקבל permission denied.\nפתרונות: הגדרת fsGroup ב-securityContext, שינוי ownership ב-Dockerfile, או הרצה כ-user עם הרשאות מתאימות."},
    {q:"ה-Namespace מוגדר עם ResourceQuota: requests.cpu=2. Pod חדש מבקש cpu: 4. מה קורה?",options:["Pod מקבל 2 cpu","Pod נדחה. עובר את ה-quota","Pod מקבל 4 cpu","Pod נשאר Pending"],answer:1,explanation:"ResourceQuota אוכפת מגבלות על צריכת משאבים ב-namespace.\nPod שדורש יותר ממה שנשאר ב-quota יידחה בזמן יצירה עם שגיאת 403."},
    {q:"ה-LimitRange מוגדר ב-namespace עם default cpu limit=500m. Pod נוצר ללא cpu limit. מה ה-cpu limit של ה-Pod?",options:["אין limit","500m מה-LimitRange","1 core","ללא הגבלה"],answer:1,explanation:"LimitRange מגדיר ערכי ברירת מחדל ל-resources.\nPod שנוצר ללא limits יקבל את ה-defaults מה-LimitRange של ה-namespace אוטומטית."},
    {q:"ה-DaemonSet מוגדר אך לא רץ על Node חדש שנוסף. מה הסיבה הסבירה?",options:["DaemonSet לא מתעדכן אוטומטית כשנוסף Node חדש","ל-Node יש Taint שה-DaemonSet לא כולל toleration בשבילו","ה-Node עדיין ב-NotReady ולכן ה-Scheduler לא משבץ עליו","ה-DaemonSet מוגבל ב-nodeSelector שלא תואם ל-Node החדש"],answer:1,explanation:"DaemonSet מריץ Pod על כל Node, אלא אם ל-Node יש Taint שה-DaemonSet לא מקבל.\nיש להוסיף toleration מתאים ל-DaemonSet spec."},
    {q:"רוצים ש-Pods של service A לא ירוצו על אותו Node כמו Pods של service B. מה מגדירים?",options:["nodeSelector עם labels שונים לכל service","pod anti-affinity עם topologyKey: kubernetes.io/hostname","taints על Nodes עם tolerations בלעדיות לכל service","topologySpreadConstraints עם maxSkew=0"],answer:1,explanation:"Pod anti-affinity עם topologyKey: kubernetes.io/hostname מבטיחה ש-Pods עם labels מסוימים לא ישכנו על אותו Node.\nשימושי ל-HA ולהפרדת workloads."},
    {q:"ה-HPA מוגדר min=2 max=10 targetCPU=50%. יש 2 Pods ב-CPU 80%. כמה Pods אחרי scale-up?",options:["10","4","3","2"],answer:1,explanation:"HPA מחשב: ceil(currentReplicas × actualMetric/targetMetric) = ceil(2 × 80/50) = ceil(3.2) = 4 replicas.\nScale-up הדרגתי, לא קפיצה למקסימום."},
    {q:"הפקודה kubectl rollout pause deployment/my-app: מה זה עושה?",options:["עוצר את כל ה-Pods","עוצר updates זמנית. שינויים נוספים לא יגרמו ל-rollout עד ל-resume","מוחק את ה-Deployment","מבצע scale=0"],answer:1,explanation:"rollout pause מאפשר לצבור מספר שינויים ב-Deployment spec ולהחיל אותם בבת אחת עם rollout resume.\nשימושי ל-canary testing."},
    {q:"ה-Pod יצא עם exit code 137. מה המשמעות?",options:["הצלחה (0)","ה-container קיבל SIGKILL: בד\"כ OOMKill","ה-container קיבל SIGTERM","שגיאת network"],answer:1,explanation:"Exit code 137 = 128+9 (SIGKILL).\nהסיבות הנפוצות: OOMKilled (kernel הרג בגלל memory limit) או kubectl delete --force.\nבודקים kubectl describe pod לאשר."},
    {q:"ה-Multi-container Pod עם sidecar. שני ה-containers צריכים לשתף קבצים. מה הפתרון?",options:["PersistentVolumeClaim משותף לשני ה-containers","emptyDir volume שמחובר לשני ה-containers","ConfigMap עם הקבצים כ-data entries","כתיבת קבצים ל-/tmp שמשותף אוטומטית בתוך Pod"],answer:1,explanation:"emptyDir נוצר עם ה-Pod ונמחק איתו.\nשני containers יכולים לחבר אותו ב-paths שונים ולשתף קבצים.\nזהו הפתרון הסטנדרטי ל-shared filesystem בתוך Pod."},
    {q:"ה-Pod מוגדר עם hostPath volume ל-/var/run/docker.sock. מה הסיכון?",options:["אין סיכון","ה-container מקבל גישה ל-Docker daemon של ה-Node. אפשר לברוח מה-container לחלוטין","רק read-only","ביצועים נמוכים"],answer:1,explanation:"גישה ל-docker.sock מאפשרת ל-container להפעיל containers אחרים על ה-Node, לקרוא secrets, ולתקוף את ה-host.\nזהו container escape vector קלאסי.\nנמנעים ממנו ב-production."},
    {q:"אחסון emptyDir עם medium: Memory מוגדר. מה שונה מ-emptyDir רגיל?",options:["נשמר לאחר restart","נשמר ב-RAM (tmpfs): מהיר יותר אבל צורך memory","מוגדל אוטומטית","נשמר ב-etcd"],answer:1,explanation:"emptyDir medium: Memory יוצר tmpfs (RAM-based filesystem).\nמהיר מאוד אבל צורך memory מה-Pod.\nשימושי ל-caches עתירי I/O.\nהנתונים נמחקים עם ה-Pod."},
    {q:"מנגנון PodSecurityAdmission ב-namespace עם enforce=restricted. Pod ניסה לרוץ ב-privileged mode. מה קרה?",options:["Pod רץ ב-privileged","Pod נדחה ב-admission","Pod רץ ב-reduced mode","RBAC מנע"],answer:1,explanation:"Policy restricted אוסרת privileged containers, hostPath volumes, running as root.\nPod שמנסה לחרוג נדחה לפני יצירה על ידי ה-admission controller."},
    {q:"ה-Pod מוגדר עם terminationGracePeriodSeconds: 0. מה קורה כשמוחקים אותו?",options:["Pod ממתין 30 שניות (ברירת מחדל)","SIGTERM ומיד SIGKILL ללא grace period. אין זמן ל-cleanup","Pod ממשיך לרוץ ומתעלם מה-delete","SIGTERM בלבד. ה-Pod ממתין עד שה-process יסיים"],answer:1,explanation:"terminationGracePeriodSeconds: 0 אומר ש-K8s שולח SIGTERM ומיד אחריו SIGKILL ללא המתנה.\nה-process לא מקבל זמן ל-cleanup.\nשימושי ב-test environments, מסוכן ב-production."},
    {q:"ה-Deployment עם strategy: Recreate. מה קורה ב-upgrade?",options:["Rolling update: Pod אחד בכל פעם","כל ה-Pods ישנים נמחקים תחילה ואז Pods חדשים נוצרים. יש downtime","אין שינוי","Blue/Green אוטומטי"],answer:1,explanation:"Recreate strategy גורמת ל-downtime מכוון.\nK8s מסיים את כל ה-Pods הישנים ורק אז יוצר חדשים.\nמתאים כשאי אפשר להריץ שתי גרסאות במקביל (single-writer DB)."},
    {q:"הפקודה kubectl apply -f secret.yaml. ה-Secret נוצר. אחר כך kubectl apply מחדש עם ערכים שונים. מה קורה?",options:["שגיאה. Secret קיים","Secret מתעדכן עם הערכים החדשים","Secret כפול נוצר","שום דבר"],answer:1,explanation:"kubectl apply הוא declarative. אם resource קיים, הוא מתעדכן לפי ה-YAML החדש.\nבניגוד ל-create שנכשל אם קיים.\nעדכון Secret עם apply חל על Pods חדשים; Pods קיימים לא מושפעים."},
    {q:"מערכת Kubernetes Ingress Controller לא מותקן. Ingress object נוצר. מה קורה?",options:["kube-proxy מטפל ב-routing במקום controller","Object נוצר ב-etcd אבל לא מתפקד. אין traffic routing","ה-API server דוחה את ה-Ingress ללא controller מותקן","ה-Ingress עובד אבל רק ל-HTTP, לא HTTPS"],answer:1,explanation:"Ingress object הוא רק ה-API definition.\nבלי Ingress Controller (nginx, traefik, ALB) שיממש אותו, ה-Ingress לא עושה כלום.\nController צריך להיות מותקן קודם."},
    {q:"ה-Pod צריך לדעת את שמו ואת ה-namespace שלו בזמן ריצה. מה משתמשים?",options:["ConfigMap שמכיל את שם ה-Pod ומעודכן אוטומטית","Downward API: מזריק metadata של ה-Pod כ-env vars או volume files","environment variables מובנים שמוזרקים מה-kubelet","קריאת API server מתוך ה-Pod עם kubectl"],answer:1,explanation:"Downward API מאפשר ל-Pod לקרוא metadata עצמי (name, namespace, labels, annotations, resources) כ-env vars או volume files. ללא ConfigMap חיצוני."},
    {q:"ה-Service Account Token מוזרק ל-Pod. מה ה-path בתוך ה-container?",options:["/etc/secrets","/var/run/secrets/kubernetes.io/serviceaccount","/sa/token","/k8s/token"],answer:1,explanation:"K8s מחבר ServiceAccount token ל-/var/run/secrets/kubernetes.io/serviceaccount/token.\nגם ca.crt ו-namespace שם.\nהאפליקציה קוראת token לשם אימות מול API server."},
    {q:"הפקודה kubectl get pods מחזיר 'The connection to the server was refused'. מה הבעיה?",options:["אין Pods באשכול ולכן אין ממה לקבל תשובה","API server לא פועל או kubeconfig מצביע ל-endpoint שגוי","ה-certificate של ה-kubeconfig פג תוקף","kubelet על ה-Node לא מצליח לתקשר עם ה-master"],answer:1,explanation:"connection refused ל-API server אומר שהתהליך לא מאזין.\nסיבות: API server crashed, kubeconfig שגוי, VPN/network בעיה.\nבודקים: kubectl config view, ping ל-API server IP."},
    {q:"פקודת Helm install נכשל: 'release already exists'. מה עושים?",options:["helm uninstall <release> ואז helm install מחדש","helm upgrade --install <release> <chart>: מטפל בשני המקרים","helm rollback <release> ואז install מחדש","helm install עם --replace flag"],answer:1,explanation:"helm install נכשל אם release קיים. helm upgrade --install ימשיך לעבוד בין אם release קיים (upgrade) ובין אם לא (install).\nפתרון אחיד לשני המקרים."},
    {q:"ה-ConfigMap מוגדר כ-env vars. ConfigMap נמחק. ה-Pod הרץ מושפע?",options:["Pod קורס מיידית","Pod ממשיך לרוץ. env vars הוזרקו בזמן יצירה","ConfigMap מוחזר אוטומטית","Pod מופעל מחדש"],answer:1,explanation:"Env vars מ-ConfigMap מוזרקים ל-Pod בזמן יצירה ונשמרים ב-memory של ה-process.\nמחיקת ConfigMap לא משפיעה על Pod רץ.\nPod חדש שינסה לעלות יכשל."},
    {q:"ה-Pod מוגדר עם activeDeadlineSeconds: 300 ב-Job. מה קורה אחרי 5 דקות?",options:["Pod מושהה","Pod מסומן כ-Failed ומסיים","Pod מופעל מחדש","שום דבר"],answer:1,explanation:"activeDeadlineSeconds מגדיר זמן מקסימלי ל-Job או Pod.\nאחרי שעבר, K8s מסיים ומסמן כ-Failed.\nשימושי למניעת Jobs שרצים לנצח."},
    {q:"תהליך Rolling update יצר שתי גרסאות שרצות במקביל. מה חשוב לוודא?",options:["feature flags שמשביתים פיצ'רים חדשים עד לסיום ה-rollout","backward compatibility: DB schema ו-API responses חייבים לתמוך בשתי גרסאות","rollback מיידי אם גרסה חדשה נכשלת ב-health check","blue/green deployment במקום rolling update"],answer:1,explanation:"בזמן rolling update שתי גרסאות רצות יחד.\nDB migrations לא יכולות להיות destructive.\nAPI responses חייבות להיות תואמות לשתי גרסאות.\nזהו עיקרון backward compatibility."},
    {q:"ה-Service ExternalName מוגדר. מה הוא עושה?",options:["פותח port חיצוני","יוצר DNS CNAME alias ל-external hostname. ללא proxying","מאפשר גישה מחוץ ל-cluster","מגדיר firewall rule"],answer:1,explanation:"ExternalName service יוצר CNAME DNS שמפנה ל-external hostname (כמו my-db.external.com).\nPods באשכול גישים לשירות חיצוני כאילו הוא internal service."},
    {q:"ברשימת initContainers: initContainer-2 ממתין ל-initContainer-1. מה ה-behavior?",options:["שניהם מתחילים במקביל","K8s ממתין ש-initContainer-1 יסיים (exit 0) לפני initContainer-2","Container הראשי מתחיל מיד","Pod נמחק"],answer:1,explanation:"init containers רצים sequentially: אחד בכל פעם.\nK8s מחכה שכל init container יסיים לפני הבא.\nרק אחרי שכולם הסתיימו, main containers עולים."},
    {q:"כלל ה-NetworkPolicy: podSelector: {} (ריק). מה זה מתאר?",options:["שום Pod","כל ה-Pods ב-namespace","כל ה-Pods בכל namespaces","שגיאה ב-syntax"],answer:1,explanation:"empty podSelector ב-NetworkPolicy policy spec בוחר כל ה-Pods ב-namespace.\nשונה מ-namespaceSelector: {} שבוחר כל ה-namespaces.\nחשוב להבדיל."},
    {q:"מערכת Kubernetes Secret גדול מ-1MiB. מה קורה?",options:["נוצר עם אזהרה","נדחה. K8s מגביל objects ל-1MiB","נוצר ב-etcd partition נפרד","Secret מחולק אוטומטית"],answer:1,explanation:"K8s אוכף גבול של 1MiB per object (Secret או ConfigMap) ב-etcd.\nלנתונים גדולים, משתמשים ב-external secret store (HashiCorp Vault, AWS Secrets Manager)."},
    {q:"ה-Pod צריך גישה ל-AWS S3 ללא credentials ב-Kubernetes. מה הגישה המומלצת?",options:["Secret עם Access Key","IRSA (IAM Roles for Service Accounts): K8s SA מחובר ל-AWS IAM Role","ConfigMap עם ARN","hostPath"],answer:1,explanation:"IRSA מאפשר ל-Pod לקבל AWS credentials זמניות דרך projected ServiceAccount token.\nללא Secret, ללא rotation ידני.\nב-GKE: Workload Identity.\nב-Azure: Workload Identity Federation."},
    {q:"ה-Pod ב-namespace prod מנסה לגשת ל-Service ב-namespace staging. מה ה-DNS הנכון?",options:["my-svc","my-svc.staging","my-svc.staging.svc.cluster.local","staging/my-svc"],answer:2,explanation:"Full DNS name ב-K8s: <service>.<namespace>.svc.cluster.local.\nלגישה ל-service ב-namespace אחר חייבים FQDN או לפחות <service>.<namespace>."},
    {q:"הפקודה kubectl cordon node1: מה ההבדל מ-drain?",options:["זהה לחלוטין","cordon מסמן Node כ-unschedulable אבל לא מסיר Pods קיימים; drain גם מסיר Pods","cordon מוחק Pods","drain לא ניתן לביטול"],answer:1,explanation:"cordon: Node לא יקבל Pods חדשים (unschedulable), Pods קיימים ממשיכים לרוץ. drain: cordon + evicts כל Pods שאינם DaemonSets. cordon בלבד משמש ל-maintenance הדרגתי."},
    {q:"ה-VPA (Vertical Pod Autoscaler) במצב Auto. מה הוא עושה?",options:["מוסיף Nodes","מכוון resources requests/limits ומפעיל Pods מחדש לפי הצורך","מגדיל replicas","לא עושה כלום"],answer:1,explanation:"VPA Auto mode: מחשב resource recommendations ומיישם אותן על ידי eviction + recreate של Pods.\nזה גורם ל-downtime קצר.\nבשל כך, VPA ו-HPA לא מומלצים יחד על אותו Deployment."},
    {q:"ה-CronJob יצר יותר ממדיניות ה-concurrencyPolicy. Pod ישן עדיין רץ. מה קורה?",options:["Job חדש נוצר תמיד","בהתאם ל-concurrencyPolicy: Forbid: Job חדש לא ייצר; Replace: Job ישן נמחק","שני Jobs רצים במקביל תמיד","CronJob מושהה"],answer:1,explanation:"concurrencyPolicy: Allow (ברירת מחדל): Jobs מקבילים.\nForbid: Job חדש לא ייצר אם קודמו עדיין רץ.\nReplace: Job ישן נמחק ונוצר חדש.\nחשוב לבחור נכון לפי workload."},
    {q:"ה-Pod צריך לרוץ על Node ספציפי לפי hostname. מה הדרך הפשוטה ביותר?",options:["nodeSelector עם label ייחודי ל-Node","nodeName: <node-name> ב-Pod spec","node affinity עם requiredDuringScheduling","taint על ה-Node עם toleration בלעדי ב-Pod"],answer:1,explanation:"nodeName שולח Pod ישירות ל-Node ספציפי, עוקף את ה-Scheduler לחלוטין.\nפשוט אך לא גמיש.\nל-production מועדפים nodeSelector או node affinity שמאפשרים label-based matching."},
    {q:"ביצעת kubectl apply על Deployment עם image חדש, אך ה-Pods ממשיכים לרוץ עם ה-image הישן. מה הסיבה הסבירה ביותר?",options:["imagePullPolicy: IfNotPresent מנע משיכת image חדש","ה-image tag (כגון latest) לא השתנה, ולכן K8s לא מזהה שינוי ב-Pod template","ה-rollout strategy מוגדר כ-Recreate אבל Pods לא נמחקו","maxSurge=0 מונע יצירת Pods חדשים עד שישנים ימחקו"],answer:1,explanation:"Kubernetes משווה את ה-Pod template hash.\nאם ה-image tag (למשל latest) לא השתנה, K8s לא רואה הבדל ולא מבצע rollout.\nיש להשתמש ב-tag ייחודי לכל build או ב-image digest (sha256)."},
    // ── Workloads extra ──
    {q:"ה-Deployment עם 3 replicas. מה קורה לאחר kubectl scale deployment/app --replicas=0?",options:["Deployment נמחק","כל ה-Pods מסתיימים; ה-Deployment נשמר ללא Pods","Pod אחד נשאר","מתקבלת שגיאה"],answer:1,explanation:"scale --replicas=0 מסיים את כל ה-Pods אבל שומר את ה-Deployment ואת ה-ReplicaSet.\nשימושי לחיסכון במשאבים בסביבות dev.\nלהחזרה: kubectl scale --replicas=3."},
    {q:"ה-Pod נתקע ב-Terminating כבר 20 דקות. kubectl delete pod לא עוזר. מה עושים?",options:["מאתחלים Node","kubectl delete pod <name> --force --grace-period=0 ובדיקת finalizers","מוחקים namespace","etcd restore"],answer:1,explanation:"Terminating תקוע לרוב בגלל finalizer שלא נוקה. kubectl patch pod <name> -p '{\"metadata\":{\"finalizers\":null}}' מסיר finalizers בכפייה. --force מאלץ מחיקה מיידית."},
    {q:"ה-Init container נכשל שוב ושוב. מה הסטטוס של ה-Pod?",options:["Running","Init:CrashLoopBackOff","Pending","Error"],answer:1,explanation:"כשinit container קורס חוזר ונשנה, Pod יציג Init:CrashLoopBackOff.\nבדוק ב-logs: kubectl logs <pod> -c <init-container-name> --previous."},
    {q:"ה-StatefulSet עם 3 replicas. Pod-1 קרס. מה Kubernetes עושה?",options:["מוחק את כולם ומתחיל מחדש","מפעיל מחדש רק Pod-1; Pods 0 ו-2 ממשיכים","מעלה Pod-3 במקום","ממתין ל-Pod-0 לקרוס"],answer:1,explanation:"StatefulSet מנהל כל Pod באופן עצמאי עם identifier קבוע.\nרק Pod-1 יופעל מחדש.\nה-PVC של Pod-1 נשמרת ומחוברת שוב ל-Pod החדש."},
    {q:"ה-DaemonSet עודכן עם image חדש. updateStrategy מוגדר כ-OnDelete. ה-Pods הקיימים עדיין מריצים את הגרסה הישנה. למה?",options:["K8s מעדכן DaemonSet רק דרך kubectl apply מחדש","עם OnDelete, Pods ישנים לא מתעדכנים עד שנמחקים ידנית","image pull נכשל בגלל imagePullPolicy: IfNotPresent","RollingUpdate לא הופעל כי חסר minReadySeconds"],answer:1,explanation:"DaemonSet תומך בשתי אסטרטגיות עדכון:\nRollingUpdate (ברירת מחדל): מעדכן Pods אוטומטית.\nOnDelete: Pods מתעדכנים רק כשנמחקים ידנית.\nבדוק: kubectl get ds <name> -o=jsonpath='{.spec.updateStrategy.type}'."},
    {q:"ה-Job עם parallelism=3, completions=9. כמה Pods ירוצו בו-זמנית בשיא?",options:["9","3","1","6"],answer:1,explanation:"parallelism=3 קובע מקסימום 3 Pods במקביל. completions=9 קובע את מספר ההצלחות הנדרשות.\nה-Job ירוץ 3 גלים של 3 Pods עד להשגת 9 הצלחות."},
    {q:"ה-Pod מסולק (Evicted). מה הסיבה הנפוצה ביותר?",options:["CPU limit חרג וה-container נהרג","Node תחת memory pressure. kubelet מסלק Pods לפי QoS","readiness probe נכשלה שוב ושוב","Image לא נמצא ב-registry"],answer:1,explanation:"kubelet עוקב אחר resource pressure.\nכשיש memory pressure, הוא מסלק Pods: BestEffort ראשון, Burstable שני, Guaranteed אחרון.\nEviction שונה ממחיקה. Controller מפעיל Pod חדש."},
    {q:"ה-Deployment עם maxUnavailable=0, maxSurge=1. מה קורה ב-rollout?",options:["Rollout לא מתחיל בגלל חוסר משאבים","Pod חדש עולה לפני שישן יורד. אין downtime","Pod ישן נמחק קודם ואז החדש עולה","כל ה-Pods מתעדכנים בו זמנית"],answer:1,explanation:"maxUnavailable=0: אי אפשר להוריד Pod עד שהחדש Ready. maxSurge=1: מותר Pod אחד נוסף מעל ה-desired.\nתוצאה: rollout ללא downtime: Pod חדש עולה ורק אז Pod ישן יורד."},
    {q:"ה-Pod עם priorityClassName גבוה. לא נמצא מקום ב-cluster. מה קורה?",options:["Pod ממתין ב-Pending ללא הגבלת זמן","Pod בעדיפות גבוהה גורם ל-preemption של Pods בעדיפות נמוכה","Pod נמחק אוטומטית אחרי timeout","priorityClass משפיע רק על סדר ב-queue, לא על preemption"],answer:1,explanation:"Preemption: ה-Scheduler מסלק Pods בעדיפות נמוכה כדי לפנות מקום ל-Pod בעדיפות גבוהה.\nחשוב להגדיר PriorityClasses בזהירות כדי למנוע פגיעה ב-workloads קריטיים."},
    {q:"ה-Namespace ללא ResourceQuota. משתמש יוצר Deployment עם 100 replicas שצורך את כל משאבי ה-cluster. מה השלכה ומה הפתרון?",options:["K8s מגביל באופן אוטומטי ל-80% מהמשאבים לכל namespace","ללא ResourceQuota, namespace אחד יכול לרוקן את משאבי כל ה-cluster","LimitRange מספיקה למנוע צריכה עודפת ברמת namespace","Node autoscaler מוסיף Nodes ומפזר עומסים אוטומטית"],answer:1,explanation:"ResourceQuota מונעת מ-namespace בודד לצרוך יותר מדי משאבים.\nללא quota, namespace אחד יכול לפגוע ב-namespaces אחרים.\nב-production מומלץ להגדיר ResourceQuota לכל namespace."},
    {q:"ה-LimitRange מגדיר default memory request=256Mi. Pod נוצר ללא memory request. מה קורה?",options:["Pod נדחה","Pod מקבל אוטומטית request=256Mi","Pod רץ ללא request","שגיאת validation"],answer:1,explanation:"LimitRange יכול להזריק default requests/limits ל-Pods שלא הגדירו.\nPod שנוצר ב-namespace עם LimitRange יקבל defaults אוטומטית."},
    {q:"ה-Pod בסטטוס Unknown. מה הסיבה?",options:["API server לא מכיר את ה-Pod","kubelet לא מדווח. בד\"כ ה-Node אינו זמין","Pod חרג מ-limits","Image לא נמצא"],answer:1,explanation:"Unknown מציין שה-Node אינו מדווח ל-control plane.\nבד\"כ קורה כשה-Node מת או מנותק. kubectl get node יציג NotReady ל-node הרלוונטי."},
    {q:"ה-HPA הגדיל Deployment ל-8 replicas בשיא העומס. העומס ירד אך replicas נשארים 8. מה מעכב scale-down?",options:["HPA לא תומך ב-scale-down, רק scale-up","stabilizationWindowSeconds (ברירת מחדל 300s) מונע scale-down מהיר","metrics-server לא מותקן ו-HPA לא מקבל נתונים","maxReplicas=8 קובע גם את ה-minReplicas בפועל"],answer:1,explanation:"HPA כולל stabilization window ל-scale-down (ברירת מחדל: 5 דקות).\nהמנגנון מונע שינויים מהירים מדי שגורמים ל-flapping.\nניתן לשנות דרך behavior.scaleDown.stabilizationWindowSeconds."},
    // ── Networking extra ──
    {q:"ה-Pod מנסה לגשת ל-Service ב-ClusterIP ומקבל Connection refused. מה בודקים?",options:["DNS resolution: ודא שה-Service name נפתר נכון","kubectl get endpoints <service>: האם יש כתובות?","targetPort שגוי: ה-Service מפנה ל-port שה-Pod לא מאזין עליו","ה-Pod לא ב-Ready ולכן לא נרשם כ-endpoint"],answer:1,explanation:"Connection refused על ClusterIP לרוב אומר שה-Service אין Endpoints.\nבדוק kubectl get endpoints. אם ריק, בעיה ב-selector שלא תואם ל-Pods.\nגם ודא שה-Pods ב-Ready."},
    {q:"ה-Ingress מחזיר 404 לכל ה-paths. Pods עולים ו-Service קיים. מה הבעיה?",options:["TLS certificate חסר או לא תקין","IngressClass לא מוגדר. Controller לא מטפל ב-Ingress","backend Service מצביע על port שגוי","Ingress ו-Service ב-namespaces שונים"],answer:1,explanation:"Ingress ב-K8s 1.18+ דורש spec.ingressClassName.\nאם חסר ול-Controller אין default IngressClass, ה-Ingress לא מטופל ומקבלים 404."},
    {q:"כלל ה-NetworkPolicy קיימת. Pod A לא מגיע ל-Pod B באותו namespace. מה בודקים?",options:["port number לא תואם בין ה-Pods","podSelector של egress ב-A ו-ingress ב-B: שניהם נדרשים","CNI plugin לא תומך ב-NetworkPolicy","Pods צריכים להיות באותו namespace כדי ש-NetworkPolicy תעבוד"],answer:1,explanation:"NetworkPolicy עובדת בשני כיוונים.\nצריך: (1) egress מ-A ל-B מאופשר, (2) ingress ל-B מ-A מאופשר.\nCNI חייב לתמוך (Calico/Cilium כן, Flannel בסיסי. לא)."},
    {q:"ה-Service selector: app=backend. ה-Pod מוגדר עם label: app=Backend (B גדולה). מה קורה?",options:["Service פועל בכל מקרה","label selectors case-sensitive. Selector לא תואם, אין Endpoints","שגיאת API","Pod לא נוצר"],answer:1,explanation:"Label selectors case-sensitive. app=backend ≠ app=Backend.\nה-Service לא יצביע על שום Pod. kubectl get endpoints <service> יציג רשימה ריקה."},
    {q:"ה-Pod לא מצליח לפתור DNS של שירות חיצוני. CoreDNS פועל. מה בודקים?",options:["CoreDNS logs ו-upstream resolver","Ingress controller שחוסם outbound traffic","resolv.conf של ה-Pod מצביע על כתובת שגויה","NetworkPolicy חוסמת egress ל-port 53"],answer:0,explanation:"CoreDNS פותר שמות חיצוניים על ידי forward ל-upstream.\nאם upstream לא מוגדר נכון ב-Corefile, DNS חיצוני ייכשל.\nבדוק גם NetworkPolicy שלא חוסמת outbound UDP 53."},
    {q:"שירות NodePort Service חשוף על port 32000. איך ניגשים מחוץ לאשכול?",options:["http://service-name:32000","http://<any-node-IP>:32000","http://ClusterIP:32000","http://localhost:32000"],answer:1,explanation:"NodePort פותח port על כל Node.\nגישה מחוץ לאשכול: http://<node-external-ip>:32000.\nאם יש LoadBalancer או Ingress עדיף להשתמש בהם."},
    {q:"ה-Pod לא מגיע ל-internet. DNS פנימי ו-ClusterIP עובדים. מה בודקים?",options:["kube-proxy לא פועל על ה-Node","NAT/masquerade מוגדר? NetworkPolicy חוסמת egress?","CoreDNS forward לא מוגדר נכון","firewall על ה-Node חוסם outbound traffic"],answer:1,explanation:"גישה ל-internet מ-Pod עוברת דרך NAT.\nבדוק: (1) kube-proxy/CNI NAT rules, (2) NetworkPolicy egress שלא חוסמת 0.0.0.0/0, (3) Firewall על ה-Node."},
    {q:"ה-Ingress עם TLS. דפדפן מציג שגיאת certificate. Secret קיים. מה בודקים?",options:["Certificate expired. בדוק תוקף עם openssl","Secret נמצא באותו namespace כמו ה-Ingress? ה-CN/SAN תואם ל-domain?","Ingress Controller לא תומך ב-TLS termination","TLS version לא נתמך על ידי הדפדפן"],answer:1,explanation:"TLS Secret חייב להיות באותו namespace כמו ה-Ingress.\nCertificate חייב להכיל CN/SAN של ה-domain.\nבדוק: kubectl describe secret <tls-secret>."},
    {q:"ה-Service קיים אבל kubectl get endpoints מחזיר ריק. מה הסיבה?",options:["Service ו-Pods ב-namespaces שונים","ה-Pods לא ב-Ready או ה-selector לא תואם","Service type=ExternalName לא יוצר Endpoints","port ב-Service לא תואם ל-targetPort"],answer:1,explanation:"Endpoints נוצרים רק כשיש Pods עם matching labels שהם גם Ready.\nבדוק: kubectl get pods --show-labels ו-Service selector."},
    {q:"שירות Headless Service (clusterIP: None). מה DNS lookup על שם ה-Service מחזיר?",options:["ClusterIP יחיד","רשימת IP של Pods ישירות","שגיאת DNS","IP של Node"],answer:1,explanation:"Headless Service אינו מקבל ClusterIP.\nDNS מחזיר A records של כל ה-Pods.\nשימושי ל-StatefulSets ול-service discovery ישיר."},
    {q:"ה-Pod מגיע ל-Pod אחר דרך DNS אבל מקבל תוצאות ישנות. מה הסיבה?",options:["CoreDNS cache לא מתעדכן בגלל בעיית sync","TTL של DNS cache: Pod מחזיק cache ישן","Service selector השתנה ו-Endpoints עדיין ישנים","kube-proxy לא עדכן את ה-iptables rules"],answer:1,explanation:"DNS responses מגיעות עם TTL.\nאפליקציות ש-cache-ות DNS עלולות להשתמש ב-IP ישן.\nפתרון: הורדת TTL ב-CoreDNS או שימוש ב-retry logic."},
    {q:"תוסף CNI plugin לא פועל על Node חדש. מה הסטטוס של Pods שמתוזמנים אליו?",options:["Running","ContainerCreating עם שגיאת network","Pending","Evicted"],answer:1,explanation:"ללא CNI פועל, K8s לא יכול להקצות IP ל-Pod. kubectl describe pod יציג שגיאת 'network plugin not ready'.\nPod יישאר ContainerCreating."},
    {q:"שני Pods צריכים לתקשר ביניהם. מה הכתובת הנכונה בתוך cluster?",options:["IP של Pod (משתנה)","<service-name>.<namespace>.svc.cluster.local","hostname של Node","IP חיצוני"],answer:1,explanation:"תמיד עדיף להשתמש ב-Service DNS name ולא ב-Pod IP שמשתנה בכל restart.\nDNS pattern: <service>.<namespace>.svc.cluster.local.\nב-namespace זהה מספיק: <service-name>."},
    // ── Config & Security extra ──
    {q:"ה-Pod מנסה לקרוא Secret כ-env var ומקבל 'secret not found'. מה בודקים?",options:["secretRef שגוי: שם ה-Secret לא תואם","Secret קיים באותו namespace כמו ה-Pod?","Secret מסוג Opaque לא נתמך כ-env var","Pod צריך ServiceAccount עם הרשאות ל-Secret"],answer:1,explanation:"Secrets scoped ל-namespace.\nPod ב-namespace A לא יכול לגשת ל-Secret ב-namespace B.\nבדוק: kubectl get secret <name> -n <pod-namespace>."},
    {q:"הפקודה kubectl get pods מחזיר 'Error from server (Forbidden)'. מה הפתרון?",options:["עדכן kubeconfig עם context חדש","הגדר RoleBinding שמקשר User או ServiceAccount ל-Role עם get/list pods","עבור ל-namespace שבו ל-user יש הרשאות","הוסף --as=admin flag לפקודה"],answer:1,explanation:"Forbidden = RBAC לא מאפשר את הפעולה.\nצריך: Role עם resources:[\"pods\"], verbs:[\"get\",\"list\"], ו-RoleBinding שמקשר ל-user/serviceaccount."},
    {q:"ה-ConfigMap עם מפתחות key1, key2. Pod מנסה לטעון key3. מה קורה?",options:["Pod רץ עם env var ריק","Pod לא עולה: 'key not found'","ConfigMap מתעדכן","namespace שגוי"],answer:1,explanation:"כשמשתמשים ב-valueFrom.configMapKeyRef עם key שלא קיים, ה-Pod לא יצליח להתחיל ויציג Event שגיאה.\nפתרון: בדוק שם המפתח ב-ConfigMap."},
    {q:"שדה imagePullSecret חסר ל-Pod שמשך image מ-private registry. מה הסטטוס?",options:["CrashLoopBackOff: ה-container עולה אבל קורס מיד","ImagePullBackOff: K8s לא מצליח לאמת מול registry","ContainerCreating: ממתין ל-image download","ErrImagePull: ה-image לא קיים ב-registry"],answer:1,explanation:"בלי imagePullSecret, kubelet לא יוכל לאמת מול private registry.\nPod יציג ImagePullBackOff.\nפתרון: kubectl create secret docker-registry + imagePullSecrets ב-Pod spec."},
    {q:"ה-Pod מנסה לרוץ כ-root אבל PodSecurity standard=restricted. מה קורה?",options:["Pod רץ כ-root","Pod נדחה. restricted מחייב runAsNonRoot:true","PodSecurity לא פעיל","warning בלבד"],answer:1,explanation:"PodSecurity Admission ב-restricted level מחייב runAsNonRoot:true, drop ALL capabilities ועוד.\nPod שלא עומד בכללים נדחה (Enforce mode)."},
    {q:"כלל ה-NetworkPolicy מגדירה default-deny-all. מה קורה לתעבורה ב-namespace?",options:["כלום לא משתנה. NetworkPolicy רק monitoring","כל ingress ו-egress נחסמים אלא אם מאפשרים במפורש","רק DNS נחסם, שאר התעבורה ממשיכה","רק HTTP/HTTPS נחסם, TCP ישיר עובד"],answer:1,explanation:"NetworkPolicy עם podSelector:{} ריק חוסמת כל תעבורה.\nיש להגדיר NetworkPolicies מפורשות לתעבורה מותרת.\nשים לב: גם DNS (port 53) נחסם!"},
    {q:"מה ההבדל בין Role ל-ClusterRole ב-RBAC?",options:["אין הבדל, שניהם פועלים בכל namespace","Role scoped ל-namespace; ClusterRole פועל על cluster-wide resources","ClusterRole רק ל-admin users; Role לכל user","Role ל-Pods בלבד; ClusterRole ל-Nodes ול-Pods"],answer:1,explanation:"Role: הרשאות ב-namespace ספציפי.\nClusterRole: הרשאות ל-cluster-wide resources (Nodes, PVs, Namespaces) או בכל namespace דרך RoleBinding."},
    {q:"ה-Secret מוגדר עם value ב-base64. מה ה-bug הנפוץ ב-encoding?",options:["base64 לא תקין ב-K8s","echo 'value' | base64 מוסיף newline. יש להשתמש ב-echo -n","Secret מוצפן פעמיים","kubectl לא תומך base64"],answer:1,explanation:"echo 'value' | base64 מוסיף newline בסוף.\nהשתמש ב-echo -n 'value' | base64.\nנתוני Secret שגויים גורמים לאפליקציה לקבל ערך עם תו נוסף."},
    {q:"הפקודה kubectl פועל עם kubeconfig שה-certificate פג תוקפו. מה ה-Error?",options:["connection refused: API server לא מאזין","Unauthorized (401): Token או Cert לא תקף","RBAC Forbidden (403): חסרות הרשאות","TLS handshake failure: גרסת TLS לא נתמכת"],answer:1,explanation:"Certificate או Token שפג תוקפו מחזיר 401 Unauthorized.\nפתרון: עדכן kubeconfig עם credentials חדשים."},
    {q:"מנגנון Admission Webhook חוסם Deploy. מה עושים?",options:["מבטלים את ה-Webhook לצמיתות","מאבחנים את הסיבה מה-message ומתקנים את ה-resource","מוחקים ה-Pod ויוצרים מחדש","מוסיפים annotation לעקוף את ה-Webhook"],answer:1,explanation:"Admission Webhooks מיישמים מדיניות.\nהמסר מסביר את הבעיה (חסר label, resource limit וכו').\nיש לתקן את ה-manifest, לא לעקוף את ה-Webhook."},
    {q:"ה-ServiceAccount של Pod מנסה לקרוא ConfigMaps אבל מקבל Forbidden. מה חסר?",options:["ConfigMap צריך annotation מיוחד לגישה מ-ServiceAccount","Role עם get/list ConfigMaps + RoleBinding ל-ServiceAccount","ServiceAccount צריך automountServiceAccountToken: true","Pod צריך securityContext.allowPrivilegeEscalation"],answer:1,explanation:"הרשאות RBAC ניתנות ל-ServiceAccount.\nצריך: Role עם resources:[\"configmaps\"], verbs:[\"get\",\"list\"], ו-RoleBinding שמקשר ל-ServiceAccount של ה-Pod."},
    {q:"ה-Pod מוגדר עם securityContext.readOnlyRootFilesystem=true. אפליקציה כותבת ל-/tmp. מה קורה?",options:["כתיבה מותרת תמיד","כתיבה ל-/tmp נכשלת אלא אם /tmp הוא emptyDir volume","Pod נדחה","Root filesystem מוצפן"],answer:1,explanation:"readOnlyRootFilesystem מונע כתיבה לכל filesystem של ה-container.\nפתרון: הרכב emptyDir volume על /tmp לאפשר כתיבה זמנית בלי לפגוע באבטחה."},
    {q:"מערכת Kubernetes Secrets: מה האמת לגבי אבטחה?",options:["Secrets מוצפנים תמיד ב-etcd כברירת מחדל","Secrets מקודדים ב-base64 בלבד, לא מוצפנים ללא EncryptionConfiguration","Secrets לא נשמרים ב-etcd אלא ב-kubelet בלבד","Secrets מוצפנים אם נוצרים עם kubectl create secret"],answer:1,explanation:"ברירת מחדל, Secrets ב-etcd מקודדים base64. לא מוצפנים.\nלהצפנה: הגדר EncryptionConfiguration ב-API server.\nלניהול secrets production: Vault, AWS Secrets Manager, External Secrets Operator."},
    // ── Storage extra ──
    {q:"ה-PVC בסטטוס Pending. StorageClass קיימת. מה בודקים?",options:["PVC גודל גדול מדי. הקטן את הדרישה","Provisioner פועל? בדוק Events של PVC","accessMode לא נתמך על ידי ה-StorageClass","PV קיים כבר ב-Released ולא ניתן ל-binding"],answer:1,explanation:"PVC Pending עם StorageClass = Provisioner לא צליח ליצור PV. kubectl describe pvc יציג Events.\nבדוק: provisioner pod רץ? Permissions? Disk quota?"},
    {q:"ה-PV עם Reclaim Policy=Retain. PVC נמחקת. מה קורה ל-PV?",options:["PV נמחק אוטומטית ומשחרר את ה-disk","PV נשאר ב-Released. נתונים שמורים אך לא ניתן לקשור PVC חדשה","PV מאופס ונעשה Available מיד לשימוש חוזר","PV משויך אוטומטית ל-PVC הבאה בתור"],answer:1,explanation:"Retain: PV לא נמחק ולא מנוקה.\nעובר ל-Released.\nלשימוש חוזר: מחק claimRef ידנית.\nDelete: PV נמחק עם ה-PVC.\nRecycle: מיושן."},
    {q:"ה-StorageClass לא קיימת. PVC מפנה אליה. מה הסטטוס?",options:["PVC נוצרת עם storage ברירת מחדל","PVC נשארת Pending עם 'storageclass not found'","PVC נמחקת","PV נוצר"],answer:1,explanation:"אם StorageClass לא קיימת, PVC תישאר Pending. kubectl describe pvc יציג: 'storageclass not found'.\nבדוק שם StorageClass נכון."},
    {q:"ה-Pod מנסה לכתוב ל-volume ומקבל Permission denied. UID=1000. מה בודקים?",options:["initContainer שמשנה permissions על ה-volume","fsGroup ב-securityContext: קובע ownership של ה-volume","runAsUser חייב להיות 0 (root) לכתיבה ל-volume","PVC accessMode צריך להיות ReadWriteMany"],answer:1,explanation:"Pod securityContext.fsGroup קובע ש-volume יהיה owned על ידי GID זה.\nאם לא מוגדר וה-volume owned על ידי root, UID 1000 לא יכול לכתוב."},
    {q:"ה-PVC עם accessMode=ReadWriteOnce. שני Pods מנסים mount. מה קורה?",options:["שניהם מקבלים גישה","Pod שני נשאר Pending. RWO מאפשר mount על Node אחד בלבד","שגיאת DNS","Eviction"],answer:1,explanation:"ReadWriteOnce: volume ניתן ל-mount כ-ReadWrite על Node אחד בלבד.\nPod שני על Node אחר יישאר Pending.\nRWX מאפשר mount על מספר Nodes."},
    {q:"כיצד מגדילים PVC קיימת?",options:["אי אפשר להגדיל PVC. יש ליצור חדשה","StorageClass עם allowVolumeExpansion:true + patch PVC עם גודל חדש","מוחקים PVC ויוצרים עם גודל חדש ללא אובדן נתונים","kubectl resize pvc עם הגודל החדש"],answer:1,explanation:"הגדלת PVC: (1) StorageClass.allowVolumeExpansion:true, (2) kubectl patch pvc עם גודל חדש.\nהגדלה online אפשרית ברוב CSI drivers; צמצום לא נתמך."},
    {q:"אחסון emptyDir מול hostPath: מה ההבדל העיקרי?",options:["אין הבדל","emptyDir: חי כל עוד Pod חי, לא persist. hostPath: mount מ-Node FS, נשאר אחרי restart","hostPath מאובטח יותר","emptyDir גדול יותר"],answer:1,explanation:"emptyDir: נוצר ריק, נמחק עם Pod. hostPath: מוסר directory מ-Node ישירות, מסוכן ב-production.\nל-shared temp storage בין containers: emptyDir."},
    {q:"ה-StatefulSet עם volumeClaimTemplate. Pod-0 נמחק ונוצר מחדש. מה קורה ל-PVC שלו?",options:["PVC נמחקת","PVC נשמרת. Pod-0 החדש מתחבר לאותה PVC","PVC חדשה נוצרת","נתונים אובדים"],answer:1,explanation:"PVCs של StatefulSet נשמרות בשם קבוע ולא נמחקות עם Pod.\nPod חדש מתחבר לאותה PVC עם אותם נתונים."},
    {q:"תהליך Dynamic provisioning לא עובד. kubectl describe pvc מציג 'waiting for volume'. מה הסיבה?",options:["PVC accessMode לא נתמך על ידי ה-provisioner","Provisioner pod לא פועל, StorageClass שגוי, או quota הגיעה","PV קיים ב-Released וחוסם את ה-provisioning","Node לא מחובר ל-storage backend"],answer:1,explanation:"dynamic provisioning דורש: (1) StorageClass עם provisioner מוגדר, (2) Provisioner pod פועל, (3) Permissions ל-provisioner, (4) cloud quota לא מוצה."},
    {q:"תהליך Volume Snapshot דורש מה?",options:["רק StorageClass","VolumeSnapshotClass + CSI driver שתומך ב-snapshots","kubectl version ספציפי","RBAC בלבד"],answer:1,explanation:"Volume Snapshots דורשים: (1) CSI driver עם snapshot capability, (2) VolumeSnapshotClass, (3) external-snapshotter controller.\nלא כל CSI drivers תומכים."},
    {q:"שרת NFS volume לא עולה: 'mount.nfs: Connection refused'. מה בודקים?",options:["Node חסר nfs-utils package","NFS server זמין? firewall port 2049? NFS exports מוגדר?","PVC accessMode צריך להיות ReadWriteMany","mount options שגויים ב-PV spec"],answer:1,explanation:"בעיות NFS: (1) NFS server לא פועל, (2) port 2049 חסום, (3) /etc/exports לא כולל IP של Node, (4) nfs-utils לא מותקן.\nבדוק לפי הסדר."},
    {q:"ה-PV נוצר עם capacity=10Gi. PVC מבקשת 5Gi. יש binding?",options:["לא. גודל חייב להיות זהה","כן. PV עם גודל גדול יותר יכול לתת ל-PVC עם דרישה קטנה יותר","PVC מקבלת 10Gi","PV מצטמצם ל-5Gi"],answer:1,explanation:"PVC binding: K8s מחפש PV שעומד בדרישות (accessMode, storageClass, גודל >= מה שמבוקש).\nPV של 10Gi יכול לתת ל-PVC של 5Gi."},
    // ── Troubleshooting extra ──
    {q:"ה-Node בסטטוס NotReady. מה הצעד הראשון?",options:["kubectl cordon node להשבתה מניעתית","kubectl describe node + ssh ל-Node + systemctl status kubelet","kubectl drain node להעברת Pods","בדוק kube-proxy logs על ה-Node"],answer:1,explanation:"NotReady = kubelet לא מדווח.\nבדוק: (1) kubectl describe node ל-Conditions, (2) ssh ל-Node, (3) systemctl status kubelet, (4) journalctl -u kubelet -n 50."},
    {q:"הפקודה kubectl exec -it pod -- /bin/bash מחזיר 'OCI runtime exec failed'. מה הסיבה?",options:["RBAC חסום: ServiceAccount ללא exec permission","bash לא קיים ב-image (distroless). נסה /bin/sh","Container לא ב-Running state","exec אפשרי רק עם kubectl debug"],answer:1,explanation:"Images כמו distroless לא כוללים bash.\nנסה: /bin/sh.\nאם גם sh לא קיים: kubectl debug -it pod --image=busybox."},
    {q:"ה-Pod restartCount=47. מה זה מסמל?",options:["Pod בריא","Pod קורס שוב ושוב. בדוק logs --previous","Pod ב-upgrade","normal behavior"],answer:1,explanation:"restartCount גבוה = Pod קורס חוזר ונשנה (CrashLoopBackOff).\nבדוק: kubectl logs <pod> --previous לשגיאת האתחול האחרונה."},
    {q:"שרת etcd ב-high disk I/O. cluster איטי. מה ההשפעה?",options:["רק Pods חדשים מושפעים, קיימים ממשיכים","API server איטי. etcd backend לכל אובייקטי K8s; latency גבוה מאט control plane","scheduling מושפע אך API responses בזמן סביר","kubelet heartbeats מושפעים ו-Nodes נראים NotReady"],answer:1,explanation:"etcd הוא ה-brain של K8s.\nכל kubectl apply/get עוברים דרך API server אל etcd. disk latency מאט את כל control plane.\nפתרון: SSD, הפחתת watch connections, etcd defrag."},
    {q:"הפקודה kubectl get pods: 'the server is currently unable to handle the request'. מה הסיבה?",options:["Pod קרס וגרם ל-cascade failure","API server rate limiting: יותר מדי requests","etcd אין מספיק מקום ב-disk","kubeconfig מצביע על endpoint לא נכון"],answer:1,explanation:"API server מגביל requests כדי למנוע עומס.\nגורמים: controllers, kubectl watch loops, CI/CD שמריץ kubectl כל שניה.\nבדוק kube-apiserver metrics."},
    {q:"שכבת ה-Container runtime (containerd) לא מגיב על Node. מה לא יעבוד?",options:["רק Pods חדשים מושפעים, קיימים ממשיכים לרוץ כרגיל","ניהול containers לא אפשרי: לא exec, לא logs חדשים, לא Pods חדשים","kubelet ממשיך לפעול אבל לא יכול לדווח status","Node עובר ל-NotReady מיד ו-Pods מפונים"],answer:1,explanation:"kubelet מתקשר עם container runtime דרך CRI.\nללא runtime: לא ניתן להפעיל containers, לבצע exec, לקחת logs.\nPods קיימים ממשיכים לרוץ ב-hardware."},
    {q:"שירות ה-kubelet certificate פג. מה קורה?",options:["kubelet עוצר ו-containers נעצרים","Node עובר ל-NotReady. TLS handshake נכשל מול API server","Pods קיימים ממשיכים לרוץ אבל לא ניתן לתזמן חדשים","API server מתעלם מה-Node ומסיר את ה-Pods"],answer:1,explanation:"kubelet מתחבר ל-API server עם client certificate.\nCertificate שפג גורם לכשל TLS handshake, ול-Node לעבור ל-NotReady.\nפתרון: Certificate Rotation (--rotate-certificates)."},
    {q:"ה-CoreDNS Pods קרסו. מה הסימפטום?",options:["Nodes עוברים ל-NotReady כי kubelet דורש DNS","DNS פנימי לא עובד. Pods לא מצליחים לפתור שמות services","Pod-to-Pod communication נפסקת לגמרי","API server לא מגיב לבקשות"],answer:1,explanation:"CoreDNS מספק service discovery.\nללא CoreDNS, Pods לא יכולים לפתור <service>.<namespace>.svc.cluster.local ואפליקציות ייכשלו."},
    {q:"שדרוג האשכול נכשל ויש צורך לחזור לגרסה הקודמת. מה הדרך הבטוחה?",options:["kubectl rollback","שחזור etcd מגיבוי שנלקח לפני השדרוג","שנמוך גרסת kubelet בכל Node","הסרת ה-control plane והתקנה מחדש"],answer:1,explanation:"הדרך האמינה לשחזור אשכול לאחר שדרוג כושל היא etcd snapshot restore.\nגיבוי etcd שומר את כל מצב האשכול, כולל משאבים, הגדרות ו-certificates.\nלכן חובה לגבות את etcd לפני כל שדרוג."},
    {q:"אחרי הוספת Node חדש לאשכול, kubectl get nodes מציג אותו כ-Ready אך Pods לא מתוזמנים אליו. מה בודקים?",options:["Node חסר labels שנדרשים ב-nodeSelector","ל-Node יש taint מסוג NoSchedule. בדוק עם kubectl describe node","Scheduler לא מכיר את ה-Node עדיין","Node resources לא דווחו ל-API server"],answer:1,explanation:"Nodes חדשים עשויים להגיע עם NoSchedule taint (למשל node.kubernetes.io/not-ready).\nרוב ה-Pods לא יתוזמנו ל-Node עם taint ללא toleration מתאימה.\nבדוק: kubectl describe node <name> | grep Taint."},
    {q:"ה-Pod לא רואה env vars מ-Secret שנוצר אחרי ה-Pod. מה קורה?",options:["Pod מתעדכן אוטומטית תוך 30 שניות","Secret כ-env var נטען רק בזמן startup. Pod ישן לא יראה Secret חדש","Secret מתפשט אוטומטית לכל Pods ב-namespace","kubelet מזריק env vars חדשים ב-sync הבא"],answer:1,explanation:"Secrets כ-env vars נטענים רק ב-container startup.\nשינויים ב-Secret לא מתעדכנים ב-Pod קיים.\nלעדכון: restart את ה-Pod.\nSecret כ-volume מתעדכן בתוך דקות."},
    {q:"כיצד בודקים שכל רכיבי ה-control plane בריאים?",options:["kubectl get all","kubectl get componentstatuses ו-kubectl get --raw '/healthz'","docker ps","netstat"],answer:1,explanation:"kubectl get componentstatuses מציג scheduler, controller-manager, etcd.\nכמו כן: kubectl get pods -n kube-system לכל ה-control plane pods.\nב-K8s חדש: kubectl get --raw '/healthz?verbose'."},
    {q:"ה-Pod יצא עם exit code 1. מה המשמעות?",options:["הצלחה","שגיאת אפליקציה כללית. ה-process דיווח על כשל","SIGKILL מה-kernel","בעיית רשת"],answer:1,explanation:"Exit code 1 = שגיאה כללית שהאפליקציה החזירה.\nבניגוד ל-137 (SIGKILL/OOM), כאן האפליקציה עצמה החליטה לצאת עם שגיאה.\nבדוק: kubectl logs <pod> --previous לפרטי השגיאה."},
    {q:"הפקודה kubectl apply מחזיר 'field is immutable'. מה עושים?",options:["מוסיפים --force flag ל-kubectl apply","מוחקים ויוצרים מחדש את ה-resource (immutable fields לא ניתנים לשינוי)","kubectl replace --force מאפשר לשנות immutable fields","kubectl patch עם strategic merge עוקף immutability"],answer:1,explanation:"חלק מ-fields ב-K8s immutable (כגון spec.selector ב-Service או Deployment).\nלשינויהם חובה: kubectl delete + kubectl apply מחדש."},
    {q:"ה-Pod רץ עם 2 containers. Container ראשון קורס. מה קורה?",options:["שני ה-containers מאותחלים ביחד","רק ה-container שקרס מאותחל, בלי תלות ב-restartPolicy","ה-Pod נמחק ונוצר מחדש על ידי ה-controller","restartPolicy קובע: Always מאתחל רק את ה-container שקרס, לא את ה-Pod"],answer:3,explanation:"ב-Pod עם מספר containers, כל container מנוהל בנפרד.\nContainer שקורס מאותחל לפי restartPolicy (Always/OnFailure/Never).\nה-Pod עצמו לא נמחק ו-containers אחרים ממשיכים לרוץ."},
    // ── Cross-language parity ──
    {q:"ה-Pod צריך לגשת ל-Kubernetes API מתוך ה-cluster. מה הכתובת הנכונה?",options:["https://kube-apiserver:6443","https://kubernetes.default.svc.cluster.local","http://localhost:8080","https://apiserver:443"],answer:1,explanation:"בתוך ה-cluster, ה-API server נגיש דרך Service מיוחד: kubernetes.default.svc.cluster.local:443.\nService זה נוצר אוטומטית ב-namespace default."},
    {q:"ה-Pod בסיווג QoS BestEffort. מה קורה בזמן memory pressure על ה-Node?",options:["לא מסולק לעולם","BestEffort Pods מסולקים ראשונים בזמן memory pressure","הם מקבלים עדיפות","הם רצים על Nodes נפרדים"],answer:1,explanation:"K8s מגדיר 3 QoS classes: Guaranteed (requests=limits), Burstable (requests<limits), BestEffort (ללא requests/limits).\nבזמן memory pressure, BestEffort מסולקים ראשונים, אחריהם Burstable, ואחרונים Guaranteed."},
    {q:"ל-Pod יש CPU limit של 200m אבל האפליקציה צורכת 500m בשיא. מה קורה?",options:["Pod נמחק","CPU throttling. ה-container רץ לאט יותר אך לא נהרג","Pod מופעל מחדש","OOMKilled"],answer:1,explanation:"CPU limit גורם ל-throttling, לא ל-eviction.\nה-container מקבל פחות CPU time ורץ לאט יותר.\nבניגוד ל-memory, חריגה מ-CPU limit לא הורגת את ה-Pod."},
    {q:"ה-ConfigMap מחובר כ-volume ל-Pod. הערך עודכן. מתי ה-Pod רואה את הערך החדש?",options:["מיידית","תוך כמה דקות (kubelet sync). ללא צורך ב-restart","רק אחרי restart של Pod","רק אחרי redeployment"],answer:1,explanation:"כש-ConfigMap מחובר כ-volume, kubelet מסנכרן שינויים תוך כ-1-2 דקות.\nהקבצים ב-volume מתעדכנים.\nאם האפליקציה קוראת את הקובץ רק ב-startup, היא עדיין תצטרך restart."},
    {q:"הפקודה kubectl rollout status deployment/my-app תקועה כבר זמן רב. מה הסיבה הנפוצה?",options:["API server עמוס ולא מגיב ל-rollout status","progressDeadlineSeconds נחרג. ה-Pod החדש לא הגיע ל-Ready","ReplicaSet ישן לא מוחק ומונע rollout","Readiness probe עם initialDelaySeconds גבוה מדי"],answer:1,explanation:"progressDeadlineSeconds (ברירת מחדל 600 שניות) קובע כמה זמן K8s ממתין ל-rollout.\nאם נחרג, ה-Deployment עובר למצב Failed.\nבדוק Events של ה-Pod כדי להבין מה מונע Ready."},
    {q:"ל-Pod יש preStop hook שנמשך 15 שניות. terminationGracePeriodSeconds מוגדר ל-10. מה קורה כשמוחקים את ה-Pod?",options:["preStop רץ 15 שניות במלואו","preStop נקטע אחרי 10 שניות וה-container מקבל SIGKILL","Pod מתעלם מ-grace period עבור preStop","שגיאה. preStop לא יכול לחרוג מ-grace period"],answer:1,explanation:"ה-grace period מכסה גם את ה-preStop hook וגם את ה-SIGTERM wait.\nאם preStop נמשך יותר מ-grace period, ה-container נהרג.\nיש להגדיר grace period ארוך מספיק לכסות את ה-preStop."},
  ],

  en: [
    // ── Workloads ──
    {q:"A pod named api-server is in CrashLoopBackOff. What is the first step to diagnose?",options:["kubectl delete pod api-server","kubectl logs api-server --previous","kubectl edit pod api-server","kubectl drain node"],answer:1,explanation:"--previous shows logs from the last crashed run.\nThis is always the first step for CrashLoopBackOff - the logs will reveal the startup error."},
    {q:"A pod stays Pending. kubectl describe shows '0/3 nodes available: 3 Insufficient memory'. What is the correct solution?",options:["Restart the pod and check its status","Move the pod to a namespace with less load","Lower the pod's memory requests or add a Node to the cluster","Delete other pods to free up memory"],answer:2,explanation:"The Scheduler can't find a Node with enough free memory to cover the requests.\nLower the pod's memory requirements or add a Node with available memory."},
    {q:"A rolling update is stuck - a new pod is created but never reaches Ready. What is the most common cause?",options:["Image does not exist in the registry","The readiness probe is failing on the new pod","Resource limits cause OOMKill on the new pod","maxUnavailable is 0 and the old pod is stuck"],answer:1,explanation:"When a rollout stalls, the most common reason is a failing readiness probe - Kubernetes waits for the pod to become Ready before updating more pods."},
    {q:"A pod crashed with OOMKilled. What does this mean and what is the next step?",options:["Network issue - check NetworkPolicy and DNS","The kernel killed the container because it exceeded its memory limit - increase limits.memory","Corrupt image - repull and restart the pod","CPU throttling causes timeout - increase CPU limits"],answer:1,explanation:"OOMKilled = Out Of Memory Killed.\nThe kernel terminated the container because it exceeded the memory limit.\nIncrease limits.memory or investigate a memory leak in the application."},
    {q:"An HPA is configured for a Deployment but doesn't scale despite high CPU. What is the most likely cause?",options:["The Deployment already reached maxReplicas","metrics-server is not installed or not running","HPA targets the wrong metric (memory instead of CPU)","Pod defines CPU limits but not requests"],answer:1,explanation:"HPA depends on metrics-server to read CPU/memory metrics.\nWithout metrics-server, HPA can't get the data it needs to make scaling decisions."},
    {q:"An init container fails every attempt with exit code 1 and logs show 'connection refused'. What do you check?",options:["DNS resolution of the target service is failing","Whether the service the init container is waiting for is actually up and running","Wrong image tag for the init container","Init container lacks network access due to NetworkPolicy"],answer:1,explanation:"Init containers are often used to wait for a dependency. 'connection refused' means the target isn't available.\nVerify the dependency service is running before the pod starts."},
    {q:"A Deployment tries to run 5 replicas but only 3 start. kubectl describe shows 'pod didn't trigger scale-up'. What do you check?",options:["Cluster autoscaler not configured or nodes can't scale out","Image not found in registry and pods fail to pull","ResourceQuota in namespace limits the number of pods","PodDisruptionBudget prevents additional replicas"],answer:0,explanation:"When pods can't be scheduled, the Cluster Autoscaler should add nodes.\nIf it doesn't - check that autoscaling is configured, no quota is full, and cloud instances are available."},
    {q:"A Job runs but never completes. kubectl get job shows COMPLETIONS 0/1 after an hour. What do you investigate?",options:["Delete the job and recreate it","kubectl logs of the Job's pod - the process is likely stuck","kubectl describe node","Change restartPolicy"],answer:1,explanation:"A job that never finishes usually has a stuck process.\nCheck the pod logs to see if it's a deadlock, waiting for input, or an infinite loop."},
    {q:"A pod shows READY 0/1 but STATUS Running. The application inside is working. What is wrong?",options:["Liveness probe failing and the pod is about to crash","Readiness probe failing - the pod won't receive traffic","Pod is still initializing and hasn't completed startup","Service selector doesn't match the pod labels"],answer:1,explanation:"0/1 Ready means the readiness probe is failing.\nThe pod runs but won't receive traffic from the Service.\nCheck the readiness probe path and port configuration."},
    {q:"A StatefulSet database-0 crashed and won't restart. kubectl describe shows 'volume is already exclusively attached'. What happened?",options:["PVC was deleted and needs to be recreated","PVC with ReadWriteOnce is attached to another node - node drain was not completed cleanly","StorageClass does not support StatefulSets","Volume reached capacity and the PVC needs expansion"],answer:1,explanation:"ReadWriteOnce allows attachment to only one node at a time.\nIf the previous node didn't fully release the volume (e.g. after a crash), the new pod can't attach it.\nWait for the node to detach or force a detach."},

    // ── Networking ──
    {q:"kubectl get endpoints my-svc shows '<none>'. The Service exists and pods are running. What is the issue?",options:["Pods didn't pass readiness check so they're not registered as endpoints","The Service selector doesn't match the pod labels","Pods are in a different namespace than the Service","Service is ExternalName type and doesn't point to pods"],answer:1,explanation:"Empty endpoints almost always mean a selector mismatch between the Service and its pods.\nCheck with kubectl get pods --show-labels."},
    {q:"A pod can't reach another service inside the cluster. curl http://my-svc.default.svc.cluster.local returns 'Could not resolve host'. What do you check?",options:["Check resolv.conf inside the pod for the correct DNS server","CoreDNS pods in kube-system - are they running and healthy?","Verify the Service exists and the name is correct","Check /etc/hosts inside the pod"],answer:1,explanation:"A DNS resolution failure inside the cluster points to CoreDNS.\nCheck: kubectl get pods -n kube-system | grep coredns and verify they are Running and Ready."},
    {q:"An Ingress is configured and DNS resolves correctly, but all requests return 404. What do you check?",options:["TLS certificate","The Ingress path rule doesn't match the path the application listens on","Ingress namespace","Pod image"],answer:1,explanation:"A 404 from Ingress usually means a path mismatch.\nIf the app listens on / but the Ingress defines path: /api, requests won't match.\nCheck path and pathType."},
    {q:"A NetworkPolicy was applied to a namespace. Now Pod A can't talk to Pod B in the same namespace. What happened?",options:["NetworkPolicy in K8s is default-deny - no allow rule was defined between the pods","The NetworkPolicy applies only to Pod A but not Pod B","The CNI plugin doesn't support NetworkPolicy enforcement","The pods use hostNetwork so NetworkPolicy doesn't apply"],answer:0,explanation:"NetworkPolicy in Kubernetes is an additive allow-list.\nWhen a policy is applied, all traffic not explicitly allowed is blocked.\nAdd an ingress rule that permits communication within the namespace."},
    {q:"A LoadBalancer Service stays in Pending (EXTERNAL-IP <pending>) on a local single-node cluster. Why?",options:["Service points to wrong port and cloud provider won't allocate IP","LoadBalancer requires cloud provider integration - unavailable locally without MetalLB","Node is not connected to external network for IP allocation","Service selector doesn't match any pods so IP is not allocated"],answer:1,explanation:"LoadBalancer type relies on a cloud provider (AWS, GCP, Azure) to allocate an external IP.\nOn local clusters (minikube, kind) this isn't available without MetalLB or similar.\nUse NodePort for local testing."},
    {q:"Pod A can't reach the internet. curl google.com fails, but another pod in the same namespace succeeds. What do you check?",options:["Check resolv.conf in the pod for DNS issues","NetworkPolicy egress rule on the specific pod that blocks outbound traffic","Check the routing table on the node where the pod runs","Pod uses a ServiceAccount with network restrictions"],answer:1,explanation:"If one pod can't reach the outside but others can, a NetworkPolicy with egress restrictions on that pod's labels is the prime suspect.\nCheck policies applied by label."},
    {q:"A ClusterIP Service is reachable from inside pods, but the NodePort on port 30080 isn't reachable from outside the cluster. What is the likely cause?",options:["Firewall / security group is blocking port 30080","Node is not listening on port 30080 because kube-proxy is down","externalTrafficPolicy: Local is set and no pod runs on the target node","NodePort is outside the allowed range (30000-32767)"],answer:0,explanation:"NodePort opens a port on all nodes, but an external firewall (security groups, iptables) may block it.\nEnsure port 30080 is open in the security group and that no iptables rule is blocking it."},

    // ── Config & Security ──
    {q:"A pod fails to access a Secret you created. kubectl describe pod shows 'secret not found'. What do you check?",options:["Secret name in pod spec differs from the created name","Whether the Secret is in the same namespace as the pod","Secret type is Opaque instead of the required type","Secret is empty so K8s ignores it"],answer:1,explanation:"Secrets and pods must be in the same namespace.\nA Secret in namespace A is not accessible to a pod in namespace B.\nVerify the Secret was created in the correct namespace."},
    {q:"A ServiceAccount tries to run kubectl get pods and gets 'Forbidden'. A Role exists. What is missing?",options:["Increase resource limits","A RoleBinding that connects the Role to the ServiceAccount","ClusterRole","Secret"],answer:1,explanation:"A Role alone is not enough.\nA RoleBinding is required to connect the Role (permissions) to the Subject (ServiceAccount).\nWithout a RoleBinding the Role has no effect."},
    {q:"A ConfigMap was updated with new values, but the app in the pod still sees old values. Why?",options:["ConfigMap is invalid and needs format validation","Most apps read ConfigMaps once at startup - the pod needs a restart","kubelet hasn't synced the ConfigMap yet - wait a few minutes","ConfigMap was set to immutable so the update was not saved"],answer:1,explanation:"When a ConfigMap is injected as env vars, changes only take effect after a pod restart.\nAs a volume, updates propagate within a few minutes - but the app must re-read the file."},
    {q:"A pod tries to pull from a private Docker registry and gets ImagePullBackOff. What is missing?",options:["Image tag doesn't exist in the registry","imagePullSecrets is not set on the pod spec - registry credentials are missing","Pod runs on a node with no network access to the registry","Pod's ServiceAccount lacks image pull permissions"],answer:1,explanation:"To pull from a private registry, the pod needs imagePullSecrets referencing a Secret of type kubernetes.io/dockerconfigjson with registry credentials."},
    {q:"A pod tries to run as root (uid 0) but is rejected. What is the likely reason?",options:["Node has a seccomp profile that blocks root","PodSecurityAdmission or PodSecurityPolicy has runAsNonRoot: true configured","Image defines USER root which triggers the error","Container runtime blocks root by default"],answer:1,explanation:"Pod Security Admission can block containers from running as root.\nIf the namespace has a restricted or baseline policy, pods requesting root will be rejected.\nChange securityContext.runAsUser."},
    {q:"A Secret is mounted as an env var: value = 'dXNlcjpwYXNz'. The app receives this string instead of 'user:pass'. What is wrong?",options:["Secret type is Opaque instead of kubernetes.io/basic-auth","Secret was created with an already base64-encoded value, so K8s decoded only one layer","Pod reads the Secret as a volume file instead of env var","Secret was defined with stringData but K8s stored it as data without conversion"],answer:1,explanation:"Kubernetes automatically decodes Secret values from base64 when injecting into pods.\nIf the Secret was created with an already-encoded value, the pod receives base64 instead of the plaintext.\nCreate the Secret with the raw value."},

    // ── Storage ──
    {q:"A PVC is Pending. kubectl describe pvc shows 'storageclass.storage.k8s.io not found'. What is the issue?",options:["PVC requests more storage than any available PV","The StorageClass specified in the PVC does not exist - check with kubectl get storageclass","PVC has no accessMode defined so binding cannot proceed","Default StorageClass exists but no provisioner is active"],answer:1,explanation:"The PVC references a StorageClass that doesn't exist.\nVerify that the storageClassName in the PVC matches one of the existing StorageClasses (kubectl get storageclass)."},
    {q:"Two pods try to mount the same PVC. The second pod stays Pending with 'Multi-Attach error'. Why?",options:["PV reached capacity and can't attach another pod","PVC with accessMode ReadWriteOnce (RWO) can only be attached to one node at a time","StorageClass doesn't support multi-attach - switch provider","Second pod runs on the same node but has a missing mount path"],answer:1,explanation:"ReadWriteOnce means the volume can only be mounted to one node at a time.\nIf two pods on different nodes try to attach it, the second is blocked.\nFix: change to ReadWriteMany if the storage backend supports it."},
    {q:"A helm upgrade fails with 'cannot patch because a resource with that name already exists (not managed by Helm)'. What happened?",options:["Chart version doesn't match the existing release - run helm rollback","A resource was manually created outside Helm so Helm doesn't manage it","Previous release wasn't fully uninstalled - run helm uninstall first","values.yaml has fields that conflict with chart defaults"],answer:1,explanation:"Helm tracks resources it created.\nIf a resource was manually created with the same name, Helm can't manage it.\nYou can annotate the resource as managed by Helm or delete it and let Helm recreate it."},
    {q:"A PV was deleted while a PVC still existed. The PVC is now in 'Lost' status. What do you do?",options:["Delete the PVC and create a new PVC with a new PV","Create a new PV with a claimRef pointing to the existing PVC","Wait for the PVC to automatically transition to Available","Edit the PVC to remove the reference to the deleted PV"],answer:1,explanation:"When a PV is deleted the PVC enters Lost status.\nCreate a new PV with spec.claimRef referencing the namespace/name of the existing PVC to restore the binding."},
    {q:"A pod tries to write to a volume but gets 'Read-only file system'. A PVC is defined in the YAML. What do you check?",options:["PV is mounted read-only at the StorageClass level","volumeMounts.readOnly: true is set on the pod spec - remove it","Container runs as non-root and lacks write permissions on the directory","PV filesystem is full so the OS blocked writes"],answer:1,explanation:"If volumeMounts has readOnly: true, the container cannot write to the volume even if the PVC allows it.\nRemove readOnly: true from volumeMounts."},

    // ── Troubleshooting ──
    {q:"A node suddenly changes to NotReady. What is the first diagnostic step?",options:["Check events with kubectl get events and node conditions","kubectl describe node and SSH to the node to check kubelet logs","Wait to see if the node recovers on its own","Cordon the node to prevent new scheduling"],answer:1,explanation:"kubectl describe node shows conditions (DiskPressure, MemoryPressure, NetworkUnavailable).\nThen SSH to the node and run: systemctl status kubelet to get details on why kubelet stopped reporting."},
    {q:"A pod has been stuck in Terminating for 30 minutes. kubectl delete doesn't help. What do you do?",options:["chmod on the pod","kubectl delete pod <name> --force --grace-period=0","kubectl restart pod","Wait an hour"],answer:1,explanation:"A stuck Terminating pod usually has a finalizer that hasn't completed. --force --grace-period=0 forces immediate deletion.\nUse with caution in production."},
    {q:"kubectl exec fails: 'error: unable to upgrade connection: container not found'. What is the reason?",options:["Pod has multiple containers and you need to specify --container","The container has already exited - the pod is likely in CrashLoop","kubelet on the node can't connect to the container runtime","Pod is in Terminating state and the container has no active PID"],answer:1,explanation:"kubectl exec opens a connection to a running container.\nIf the container has exited (CrashLoop), there is no container to exec into.\nCheck logs and fix the crash cause."},
    {q:"The cluster autoscaler is not adding nodes despite pods being Pending. What do you check?",options:["Check events on Pending pods with kubectl describe pod","Logs of the cluster-autoscaler pod - possible taint mismatch, quota, or no available instance type","Check node capacity with kubectl describe node to find bottleneck","Check cloud provider quota and region limits"],answer:1,explanation:"The autoscaler adds nodes only if it determines new pods could run on the new node.\nIf there's an unmatched taint, a full quota, or a cloud provider issue, it won't add nodes."},
    {q:"A node is showing DiskPressure. Pods start getting evicted. What is the quick fix?",options:["Add a new node to the cluster to spread the load","Clean up images, logs, and temp files on the node - docker system prune","Increase ephemeral-storage limits on the pods","Enable log rotation in kubelet configuration"],answer:1,explanation:"DiskPressure occurs when the node's disk fills up.\nQuick fix: SSH to the node, prune unused images (docker/crictl image prune) and old logs.\nLong-term: expand disk or implement log rotation."},
    {q:"kubectl top nodes fails: 'error: Metrics API not available'. What is missing?",options:["kubelet is not reporting metrics - check its configuration","metrics-server is not installed in the cluster","API server is not configured with the aggregation layer","Nodes don't expose port 10250 to metrics-server"],answer:1,explanation:"kubectl top requires metrics-server which provides CPU/memory metrics.\nWithout it, HPA won't work either.\nInstall: kubectl apply -f https://github.com/kubernetes-sigs/metrics-server/releases/latest/download/components.yaml"},
    {q:"kubectl drain node1 is blocked: 'cannot delete Pods not managed by ReplicationController, ReplicaSet, Job, DaemonSet, or StatefulSet'. What do you do?",options:["kubectl delete node","Add --force --ignore-daemonsets","kubectl uncordon","Create a PDB"],answer:1,explanation:"kubectl drain is blocked by standalone pods (without a controller). --force allows deleting them. --ignore-daemonsets skips DaemonSet pods that can't be moved."},
    {q:"A liveness probe on path /healthz is failing every 30 seconds, causing the container to restart. The app is actually working. What do you check?",options:["initialDelaySeconds is too short and the app hasn't started yet","The liveness probe is hitting the wrong port or path, or the response is not a 2xx/3xx status","timeoutSeconds is too short and the probe times out before response","Container is too slow to respond to probe requests in time"],answer:1,explanation:"If the app works but the liveness probe fails, the probe is likely misconfigured - wrong port, wrong path, or the health endpoint returns a non-success status.\nVerify the path and port match the app's health endpoint."},
    {q:"After kubectl rollout undo, the Deployment reverted but the app is still broken. What do you check?",options:["Deployment is still in the middle of a rollout - wait","The undo may have reverted to a revision that was also broken - check rollout history and select a specific revision","ConfigMap or Secrets used by the previous revision have changed","The new pod started but readiness probe is still failing"],answer:1,explanation:"kubectl rollout undo reverts to the previous revision, but if that was also broken it won't help.\nUse kubectl rollout history deployment/my-app to see all revisions, then rollout undo --to-revision=N."},
    {q:"kubectl apply -f manifest.yaml succeeds with no error, but the resource is not created where expected. What do you check?",options:["API server accepted the request but an admission webhook rejected it","Resource was created in a different namespace - check events and kubectl get across all namespaces","YAML contains an old apiVersion and the resource was created with a different schema","YAML is empty or the kind is not recognized by the API server"],answer:1,explanation:"apply succeeds at the API level but the resource is created in the namespace defined in the YAML (which may be wrong) or in default.\nCheck: kubectl get <resource> --all-namespaces."},
    {q:"A new pod can't be scheduled on any node. kubectl describe pod shows Taints. What is the fix?",options:["Remove the taint from nodes with kubectl taint nodes","Add a toleration to the pod spec that matches the node taint","Add a nodeSelector to the pod pointing to a specific node","Increase resource requests so the scheduler finds a suitable node"],answer:1,explanation:"When a node has a taint, only pods with a matching toleration can run on it.\nAdd a tolerations entry to the pod spec that matches the taint (key, operator, effect)."},
    {q:"An etcd pod in kube-system is showing issues. How many etcd members should a healthy production cluster have?",options:["1","2","3 (or any odd number)","Exactly 5"],answer:2,explanation:"etcd requires quorum - a majority of members must be available. 3 members tolerate 1 failure; 5 tolerate 2.\nAlways use an odd number to prevent split-brain.\nProduction typically uses 3 or 5."},
    {q:"A namespace is stuck in Terminating for over an hour. What is the most likely cause?",options:["API server failed to update the resource","Finalizers on resources inside the namespace are preventing deletion","Node running namespace workloads is unavailable","Namespace controller requires a manual restart"],answer:1,explanation:"A namespace stuck in Terminating is almost always blocked by finalizers that haven't been cleared.\nIdentify resources with finalizers (often CRDs) and remove them manually or patch the namespace to remove the finalizers."},
    {q:"A pod is running on node1. kubectl drain node1 is executed. What happens next?",options:["Kubernetes immediately live-migrates the pod to another node","drain terminates the pod; the owning controller (Deployment) creates a new pod on another node","Pod stays on the node until the cordon is removed","Scheduler waits for a 5-minute cooldown period"],answer:1,explanation:"kubectl drain terminates pods on the node.\nThe Deployment controller notices the missing replica and creates a new pod, which the Scheduler places on a non-cordoned node."},
    {q:"RBAC is configured with a ClusterRole but you only want it to apply to a specific namespace. Which binding do you use?",options:["ClusterRoleBinding only","RoleBinding - allows using a ClusterRole but scopes permissions to the namespace of the RoleBinding","A new Role with the same permissions in the namespace","ServiceAccount token with ClusterRole embedded"],answer:1,explanation:"A RoleBinding can reference a ClusterRole, but it restricts the permissions to the namespace where the RoleBinding lives.\nClusterRoleBinding grants cluster-wide access.\nFor scoped access use a RoleBinding pointing to a ClusterRole."},
    {q:"A pod in namespace prod tries to access a ConfigMap from namespace staging. What happens?",options:["It works automatically across namespaces","Pods cannot directly access resources in other namespaces","It works only if both namespaces are on the same node","A ResourceQuota allowing cross-namespace access is needed"],answer:1,explanation:"Pods access ConfigMaps, Secrets, and other resources only within their own namespace.\nTo share data across namespaces, duplicate the resource or use an external config store."},
    {q:"A readinessGate is defined on a pod. The pod shows READY 0/1 even though the readiness probe passes. What do you check?",options:["Liveness probe is failing causing restarts before pod becomes Ready","The readinessGate condition is not satisfied - set by an external controller (e.g. load balancer sync)","Container is still in image pull phase","Service selector doesn't match so the pod is not registered as Ready"],answer:1,explanation:"ReadinessGates let external controllers determine pod readiness.\nThe pod is only Ready after the additional condition (e.g. network LB sync) is set to True in pod status.\nCheck the custom conditions."},
    {q:"You apply a PodDisruptionBudget. kubectl drain fails: 'Cannot evict pod as it would violate the pod disruption budget'. What happened?",options:["Node is already cordoned so drain can't run again","PDB defines minAvailable=2 but only 2 pods exist - drain would reduce below minimum","Pod uses a local PV that can't be moved","Deployment has maxUnavailable=0 configured"],answer:1,explanation:"PDB defines how many pods must remain available.\nIf drain would reduce the count below minAvailable, it is blocked.\nFix: ensure enough replicas exist before draining, or temporarily scale up the Deployment."},
    {q:"While debugging, you run kubectl exec pod -- env and see SECRET_KEY is missing. What do you check?",options:["Pod's ServiceAccount lacks permissions to read Secrets","Secret doesn't exist in the namespace or secretKeyRef in the YAML is incorrect","Secret is encrypted so env vars aren't directly exposed","Pod needs a restart after the Secret is created"],answer:1,explanation:"When a Secret-sourced env var is missing, check: the Secret exists, secretName is correct, key is correct, and namespace matches.\nUse kubectl get secret <name> -n <namespace> and kubectl describe pod."},
    {q:"Pod A tries to reach Pod B on port 8080 and gets connection refused. No NetworkPolicy is configured. What do you check?",options:["Pod B is not listening on port 8080 - the process may not have started or listens on a different port","kube-proxy is not updating iptables rules correctly","Pods are on different nodes and CNI is not configured","Pod B's Service doesn't include port 8080 in its spec"],answer:0,explanation:"Without NetworkPolicy, traffic is unrestricted at the network level.\nConnection refused means no process is listening on that port.\nCheck: kubectl exec podB -- ss -tlnp."},
    {q:"A Deployment with 3 replicas has all pods in ImagePullBackOff. kubectl describe shows 'Back-off pulling image'. What is the first step?",options:["Check node resources - disk may be too full to pull images","Check the image tag in the YAML - does the tag exist in the registry?","Restart kubelet on all nodes","Check if imagePullPolicy is set to Always"],answer:1,explanation:"ImagePullBackOff means the image can't be pulled.\nCommon causes: tag doesn't exist, wrong image name, or missing imagePullSecrets for a private registry. kubectl describe pod shows the exact image name being requested."},
    {q:"You want pods to be spread across availability zones for HA. What is the best approach?",options:["Node affinity with zone labels","topologySpreadConstraints with topologyKey: topology.kubernetes.io/zone","Pod anti-affinity with topologyKey: topology.kubernetes.io/zone","Set replicas equal to the number of zones"],answer:1,explanation:"topologySpreadConstraints spread pods evenly across zones (or nodes, racks).\nConfigure maxSkew and topologyKey for zone.\nThis is preferred over pod anti-affinity as it is more flexible and scalable."},
    {q:"A pod is in CrashLoop. Logs show 'permission denied' on path /data. What is the issue?",options:["Volume was not properly mounted to /data","The container runs as a user without write permissions - check securityContext and fsGroup","Image is missing the /data directory in its filesystem","PVC is configured as ReadOnlyMany"],answer:1,explanation:"When a process inside a container can't write to a path, check securityContext.\nSolutions: set fsGroup so the group owns the mounted volume, fix ownership in the Dockerfile, or run as a user with appropriate permissions."},
    {q:"A namespace has a ResourceQuota of requests.cpu=2. A new pod requests cpu: 4. What happens?",options:["Pod gets 2 cpu","Pod is rejected - it exceeds the quota","Pod gets 4 cpu","Pod stays Pending"],answer:1,explanation:"ResourceQuota enforces resource consumption limits per namespace.\nA pod requesting more than the remaining quota is rejected at creation time with a 403 error."},
    {q:"A LimitRange in a namespace sets a default cpu limit of 500m. A pod is created with no cpu limit. What is the pod's cpu limit?",options:["No limit","500m from the LimitRange","1 core","Unlimited"],answer:1,explanation:"LimitRange provides default values for resources.\nA pod created without limits automatically receives the LimitRange defaults for that namespace."},
    {q:"A DaemonSet is defined but not running on a newly added node. What is the most likely reason?",options:["DaemonSet doesn't auto-update when a new node is added","The node has a taint the DaemonSet has no toleration for","Node is still NotReady so the Scheduler won't schedule on it","DaemonSet has a nodeSelector that doesn't match the new node"],answer:1,explanation:"DaemonSets run a pod on every node unless the node has a taint that the DaemonSet doesn't tolerate.\nAdd the appropriate toleration to the DaemonSet spec."},
    {q:"You want pods of service A to never run on the same node as pods of service B. What do you configure?",options:["nodeSelector with different labels for each service","Pod anti-affinity with topologyKey: kubernetes.io/hostname","Taints on nodes with exclusive tolerations per service","topologySpreadConstraints with maxSkew=0"],answer:1,explanation:"Pod anti-affinity with topologyKey: kubernetes.io/hostname ensures pods with certain labels don't share a node.\nUseful for HA and workload separation."},
    {q:"An HPA is set min=2 max=10 targetCPU=50%. 2 pods are at 80% CPU. How many pods after scale-up?",options:["10","4","3","2"],answer:1,explanation:"HPA formula: ceil(currentReplicas × actual/target) = ceil(2 × 80/50) = ceil(3.2) = 4 replicas.\nScale-up is gradual, not a jump to maximum."},
    {q:"kubectl rollout pause deployment/my-app - what does this do?",options:["Stops all pods","Suspends rollout updates - further spec changes won't trigger a rollout until resume","Deletes the Deployment","Scales to 0"],answer:1,explanation:"rollout pause lets you batch multiple Deployment spec changes and apply them all at once with rollout resume.\nUseful for canary testing and multi-step changes."},
    {q:"A pod exited with code 137. What does this mean?",options:["Success (0)","The container received SIGKILL - typically OOMKill","The container received SIGTERM","Network error"],answer:1,explanation:"Exit code 137 = 128+9 (SIGKILL).\nCommon causes: OOMKilled (kernel killed for exceeding memory limit) or kubectl delete --force.\nCheck kubectl describe pod to confirm."},
    {q:"A multi-container pod needs both containers to share files. What is the standard solution?",options:["A shared PersistentVolumeClaim for both containers","An emptyDir volume mounted by both containers","A ConfigMap with files as data entries","Writing to /tmp which is automatically shared within a pod"],answer:1,explanation:"emptyDir is created with the pod and deleted with it.\nBoth containers can mount it at different paths to share files.\nThis is the standard solution for intra-pod shared storage."},
    {q:"A pod mounts a hostPath volume at /var/run/docker.sock. What is the security risk?",options:["No risk","The container gains access to the Node's Docker daemon - full container escape is possible","Read-only access only","Performance degradation"],answer:1,explanation:"Mounting docker.sock lets a container spawn containers on the host, read secrets, and escape the container sandbox entirely.\nThis is a classic container escape vector and must be avoided in production."},
    {q:"An emptyDir volume is configured with medium: Memory. How does it differ from a regular emptyDir?",options:["Data persists after restart","Data is stored in RAM (tmpfs) - faster but consumes pod memory","Size scales automatically","Data is stored in etcd"],answer:1,explanation:"emptyDir medium: Memory creates a tmpfs (RAM-based filesystem).\nVery fast for high-throughput I/O but counts against the pod's memory budget.\nData is lost when the pod terminates."},
    {q:"PodSecurityAdmission is set to enforce=restricted on a namespace. A pod tries to run in privileged mode. What happens?",options:["Pod runs privileged","Pod is rejected at admission","Pod runs in reduced mode","RBAC blocks it"],answer:1,explanation:"The restricted policy forbids privileged containers, hostPath volumes, and running as root.\nThe pod is rejected before creation by the admission controller."},
    {q:"A pod has terminationGracePeriodSeconds: 0. What happens when it is deleted?",options:["Pod waits 30 seconds (default)","SIGTERM then immediate SIGKILL with no grace period - no cleanup time","Pod keeps running and ignores the delete","SIGTERM only - pod waits until the process exits"],answer:1,explanation:"terminationGracePeriodSeconds: 0 causes Kubernetes to send SIGTERM followed immediately by SIGKILL with no grace period.\nThe process has no time to clean up.\nUse only in test environments."},
    {q:"A Deployment uses strategy: Recreate. What happens during an upgrade?",options:["Rolling update - one pod at a time","All old pods are terminated first, then new ones are created - causes downtime","No change","Automatic blue/green"],answer:1,explanation:"Recreate strategy causes intentional downtime.\nKubernetes terminates all old pods before creating new ones.\nSuitable when two versions cannot run simultaneously (e.g. single-writer database)."},
    {q:"kubectl apply is run twice on the same Secret YAML with different values. What happens?",options:["Error - Secret already exists","Secret is updated with the new values","A duplicate Secret is created","Nothing"],answer:1,explanation:"kubectl apply is declarative - if the resource exists it is updated to match the new YAML.\nUnlike create which fails if the resource exists.\nExisting running pods are not affected."},
    {q:"An Ingress Controller is not installed. An Ingress object is created. What happens?",options:["kube-proxy handles routing instead of a controller","The object is stored in etcd but has no effect - no traffic routing occurs","API server rejects the Ingress without an installed controller","Ingress works but only for HTTP, not HTTPS"],answer:1,explanation:"An Ingress object is only an API definition.\nWithout an Ingress Controller (nginx, traefik, ALB) to implement it, it does nothing.\nThe controller must be installed first."},
    {q:"A pod needs to know its own name and namespace at runtime. What mechanism do you use?",options:["ConfigMap that contains the pod name and auto-updates","Downward API - injects pod metadata as env vars or volume files","Built-in environment variables injected by kubelet","Reading API server from inside the pod with kubectl"],answer:1,explanation:"The Downward API lets a pod read its own metadata (name, namespace, labels, annotations, resource limits) as env vars or files - without any external ConfigMap."},
    {q:"Where is the ServiceAccount token mounted inside a container?",options:["/etc/secrets","/var/run/secrets/kubernetes.io/serviceaccount","/sa/token","/k8s/token"],answer:1,explanation:"Kubernetes mounts the ServiceAccount token at /var/run/secrets/kubernetes.io/serviceaccount/token.\nThe ca.crt and namespace are also there.\nThe app reads the token to authenticate to the API server."},
    {q:"kubectl get pods returns 'The connection to the server was refused'. What is the problem?",options:["No pods exist so there's nothing to return","The API server is down or kubeconfig points to a wrong endpoint","The kubeconfig certificate has expired","kubelet on the node can't communicate with the master"],answer:1,explanation:"'connection refused' to the API server means the process isn't listening.\nCauses: API server crashed, wrong kubeconfig endpoint, VPN/network issue.\nCheck: kubectl config view, ping the API server IP."},
    {q:"helm install fails: 'release already exists'. What is the solution?",options:["helm uninstall <release> then helm install again","helm upgrade --install <release> <chart> - works whether the release exists or not","helm rollback <release> then install again","helm install with --replace flag"],answer:1,explanation:"helm install fails if the release already exists. helm upgrade --install handles both cases: upgrade if it exists, install if it doesn't.\nThe go-to solution for CI/CD pipelines."},
    {q:"A ConfigMap is used as env vars. The ConfigMap is deleted. Does the running pod notice?",options:["Pod crashes immediately","Pod keeps running - env vars were injected at creation time","ConfigMap is auto-recreated","Pod restarts"],answer:1,explanation:"Env vars from a ConfigMap are injected at pod creation and stored in the process's memory.\nDeleting the ConfigMap has no effect on a running pod.\nA new pod will fail to start."},
    {q:"A Job has activeDeadlineSeconds: 300. What happens after 5 minutes?",options:["Pod is paused","Pod is marked Failed and terminated","Pod restarts","Nothing"],answer:1,explanation:"activeDeadlineSeconds sets a maximum runtime for a Job.\nAfter the deadline, Kubernetes terminates the pod and marks it Failed.\nUseful to prevent Jobs from running indefinitely."},
    {q:"A rolling update runs two versions simultaneously. What must you ensure?",options:["Feature flags to disable new features until rollout completes","Backward compatibility - DB schema and API responses must work for both versions","Immediate rollback if the new version fails health checks","Blue/green deployment instead of rolling update"],answer:1,explanation:"During a rolling update both versions run together.\nDB migrations must not be destructive (no dropped columns).\nAPI responses must be compatible with both versions.\nThis is the backward compatibility principle."},
    {q:"A Service of type ExternalName is defined. What does it do?",options:["Opens an external port","Creates a DNS CNAME alias to an external hostname - no proxying","Allows external access to the cluster","Defines a firewall rule"],answer:1,explanation:"ExternalName creates a CNAME DNS record pointing to an external hostname (e.g. my-db.external.com).\nPods access the external service as if it were an internal service, without needing IP addresses."},
    {q:"init containers are listed in sequence. initContainer-2 is waiting. What is the behavior?",options:["Both start in parallel","Kubernetes waits for initContainer-1 to exit 0 before starting initContainer-2","Main container starts immediately","Pod is deleted"],answer:1,explanation:"Init containers run sequentially - one at a time.\nKubernetes waits for each to complete (exit 0) before starting the next.\nOnly after all init containers finish do the main containers start."},
    {q:"A NetworkPolicy has podSelector: {} (empty). What does this select?",options:["No pods","All pods in the namespace","All pods in all namespaces","Syntax error"],answer:1,explanation:"An empty podSelector in a NetworkPolicy selects all pods in the namespace.\nThis differs from namespaceSelector: {} which selects all namespaces.\nImportant distinction for writing policies."},
    {q:"A Kubernetes Secret exceeds 1MiB. What happens?",options:["Created with a warning","Rejected - Kubernetes enforces a 1MiB object size limit","Stored in a separate etcd partition","Automatically split"],answer:1,explanation:"etcd and Kubernetes enforce a ~1MiB limit per object (Secret/ConfigMap).\nFor larger data, use an external secret store (HashiCorp Vault, AWS Secrets Manager) and inject references."},
    {q:"A pod needs access to AWS S3 without storing credentials in Kubernetes. What is the recommended approach?",options:["Secret with Access Key","IRSA (IAM Roles for Service Accounts) - K8s SA mapped to AWS IAM Role","ConfigMap with ARN","hostPath"],answer:1,explanation:"IRSA allows pods to receive temporary AWS credentials via a projected ServiceAccount token.\nNo Secrets, no manual rotation.\nGKE equivalent: Workload Identity.\nAzure: Workload Identity Federation."},
    {q:"A pod in namespace prod needs to reach a service in namespace staging. What DNS name is correct?",options:["my-svc","my-svc.staging","my-svc.staging.svc.cluster.local","staging/my-svc"],answer:2,explanation:"The full K8s DNS name is: <service>.<namespace>.svc.cluster.local.\nTo reach a service in another namespace you must use the FQDN or at minimum <service>.<namespace>."},
    {q:"What is the difference between kubectl cordon and kubectl drain?",options:["They are identical","cordon marks a node unschedulable but doesn't remove existing pods; drain also evicts existing pods","cordon deletes pods","drain cannot be undone"],answer:1,explanation:"cordon: node won't accept new pods, existing pods keep running. drain: cordon + evicts all non-DaemonSet pods.\nUse cordon alone for gradual maintenance without disrupting running workloads."},
    {q:"A VPA is in Auto mode. What does it do?",options:["Adds nodes","Adjusts resource requests/limits and restarts pods as needed","Increases replica count","Does nothing"],answer:1,explanation:"VPA Auto mode calculates resource recommendations and applies them by evicting and recreating pods.\nThis causes brief downtime.\nVPA and HPA are generally not recommended together on the same Deployment."},
    {q:"A CronJob has concurrencyPolicy: Forbid. The previous job is still running when the next is scheduled. What happens?",options:["A new job is always created","The new job is skipped - Forbid prevents concurrent runs","Both jobs run in parallel","CronJob is suspended"],answer:1,explanation:"concurrencyPolicy: Allow (default) - concurrent jobs OK.\nForbid - skip new job if previous still running.\nReplace - delete old job and create new one.\nChoose based on workload requirements."},
    {q:"You want a pod to run on a specific node by hostname. What is the simplest approach?",options:["nodeSelector with a unique label for the node","nodeName: <node-name> in pod spec","node affinity with requiredDuringScheduling","Taint on the node with an exclusive toleration in the pod"],answer:1,explanation:"nodeName sends the pod directly to a specific node, bypassing the Scheduler entirely.\nSimple but inflexible.\nFor production, prefer nodeSelector or node affinity which use label-based matching."},
    {q:"A pod needs to access the Kubernetes API from inside the cluster. What is the API server address?",options:["https://kube-apiserver:6443","https://kubernetes.default.svc.cluster.local","http://localhost:8080","https://apiserver:443"],answer:1,explanation:"Inside the cluster, the API server is accessible via the special Service: kubernetes.default.svc.cluster.local:443.\nThis ClusterIP Service is created automatically in the default namespace."},
    {q:"After a kubectl apply, the Deployment doesn't update. The old image is still running. What do you check?",options:["imagePullPolicy: IfNotPresent prevented pulling the new image","The image tag (e.g. latest) didn't change so K8s sees no diff in the pod template","Rollout strategy is Recreate but pods weren't deleted","maxSurge=0 prevents new pods until old ones are removed"],answer:1,explanation:"Kubernetes detects changes by hashing the pod template.\nIf the image tag (like 'latest') didn't change, Kubernetes sees no diff and skips the rollout.\nUse a unique tag or image digest (sha256) per build."},
    {q:"A pod QoS class is BestEffort. What happens during memory pressure?",options:["It is never evicted","BestEffort pods are evicted first during memory pressure","They are prioritised","They run on separate nodes"],answer:1,explanation:"Kubernetes defines 3 QoS classes: Guaranteed (requests=limits), Burstable (requests<limits), BestEffort (no requests/limits).\nDuring memory pressure, BestEffort is evicted first, then Burstable, then Guaranteed."},
    {q:"A pod has a CPU limit of 200m but the app needs 500m at peak. What happens?",options:["Pod is deleted","CPU throttling - the container runs slower but is not killed","Pod is restarted","Pod is OOMKilled"],answer:1,explanation:"CPU limit causes throttling, not eviction.\nThe container gets less CPU time and runs slower.\nUnlike memory, exceeding CPU limit does not kill the pod.\nThis is an important distinction."},
    {q:"A ConfigMap is mounted as a volume. Its value is updated. When does the pod see the new value?",options:["Immediately","Within a few minutes (kubelet sync TTL) - no restart needed","Only after pod restart","Only after redeployment"],answer:1,explanation:"When a ConfigMap is mounted as a volume, kubelet syncs changes within about 1-2 minutes.\nThe files in the volume are updated in place.\nHowever, if the app reads the file only at startup it still needs a restart."},
    {q:"kubectl rollout status deployment/my-app is stuck for a long time. What is a common cause to check?",options:["API server is overloaded and not responding to rollout status","progressDeadlineSeconds exceeded - the new pod never reached Ready","Old ReplicaSet is not being cleaned up and blocks rollout","Readiness probe has a high initialDelaySeconds"],answer:1,explanation:"progressDeadlineSeconds (default 600s) defines how long Kubernetes waits for a rollout to succeed.\nIf exceeded, the Deployment enters a Failed condition.\nCheck pod events to find why the pod isn't reaching Ready."},
    // ── Workloads extra ──
    {q:"You run kubectl scale deployment/app --replicas=0. What happens?",options:["Deployment is deleted","All pods terminate; the Deployment object is preserved","One pod remains","An error is returned"],answer:1,explanation:"Scaling to 0 terminates all pods but keeps the Deployment and ReplicaSet intact.\nUseful for saving resources in dev environments.\nScale back with --replicas=N."},
    {q:"A pod is stuck in Terminating for 20 minutes. kubectl delete has no effect. What do you do?",options:["Reboot the node","kubectl delete pod <name> --force --grace-period=0 and check for finalizers","Delete the namespace","etcd restore"],answer:1,explanation:"Stuck Terminating is usually caused by a finalizer that hasn't been cleared.\nRemove them with: kubectl patch pod <name> -p '{\"metadata\":{\"finalizers\":null}}'. --force bypasses the graceful period."},
    {q:"An init container is failing repeatedly. What pod status do you see?",options:["Running","Init:CrashLoopBackOff","Pending","Error"],answer:1,explanation:"When an init container crashes repeatedly, the pod shows Init:CrashLoopBackOff.\nDebug with: kubectl logs <pod> -c <init-container-name> --previous."},
    {q:"A StatefulSet has 3 replicas. Pod-1 crashes. What does Kubernetes do?",options:["Deletes all pods and restarts","Restarts only Pod-1; pods 0 and 2 continue running","Creates Pod-3 as replacement","Waits for Pod-0 to crash first"],answer:1,explanation:"StatefulSet manages each pod independently with a stable identity.\nOnly the failed pod is restarted.\nIts PVC is retained and reattached to the new pod."},
    {q:"A DaemonSet was updated with a new image. updateStrategy is set to OnDelete. Existing pods still run the old version. Why?",options:["K8s updates DaemonSets only through kubectl apply","With OnDelete, existing pods are not updated until manually deleted","Image pull failed due to imagePullPolicy: IfNotPresent","RollingUpdate didn't trigger because minReadySeconds is missing"],answer:1,explanation:"DaemonSet supports two update strategies:\nRollingUpdate (default): updates pods automatically.\nOnDelete: pods update only when manually deleted.\nCheck: kubectl get ds <name> -o=jsonpath='{.spec.updateStrategy.type}'."},
    {q:"A Job has parallelism=3, completions=9. How many pods run at peak?",options:["9","3","1","6"],answer:1,explanation:"parallelism=3 means at most 3 pods run concurrently. completions=9 defines the success target.\nThe Job runs 3 waves of 3 pods until 9 successful completions."},
    {q:"A pod is Evicted from a node. What is the most common reason?",options:["CPU limit exceeded and container was killed","Node under memory pressure - kubelet evicts by QoS class","Readiness probe failed repeatedly","Image not found in the registry"],answer:1,explanation:"kubelet watches resource pressure.\nUnder memory pressure it evicts: BestEffort first, Burstable second, Guaranteed last.\nEviction differs from deletion - the controller recreates the pod."},
    {q:"A Deployment has maxUnavailable=0, maxSurge=1. What does this mean for rollouts?",options:["Rollout doesn't start due to lack of resources","New pod comes up before old goes down - zero downtime","Old pod is deleted first then new one comes up","All pods are updated simultaneously"],answer:1,explanation:"maxUnavailable=0: no pod can go down until the new one is Ready. maxSurge=1: one extra pod allowed above desired.\nResult: zero-downtime rolling update - new pod up → old pod down."},
    {q:"A pod has a high priorityClassName. No resources are free. What happens?",options:["Pod waits in Pending indefinitely","High-priority pod triggers preemption of lower-priority pods","Pod is deleted automatically after a timeout","priorityClass only affects queue order, not preemption"],answer:1,explanation:"Preemption: the Scheduler evicts lower-priority pods to make room for a high-priority pod.\nDefine PriorityClasses carefully to avoid disrupting critical workloads."},
    {q:"A namespace has no ResourceQuota. A user creates a Deployment with 100 replicas that consumes all cluster resources. What is the impact and fix?",options:["K8s automatically limits each namespace to 80% of resources","Without ResourceQuota, one namespace can exhaust the entire cluster","LimitRange is sufficient to prevent namespace-level overconsumption","Node autoscaler adds nodes and distributes load automatically"],answer:1,explanation:"ResourceQuota prevents any single namespace from consuming excessive resources.\nWithout it, one namespace can starve others.\nIn production, always define ResourceQuota per namespace."},
    {q:"A LimitRange sets default memory request=256Mi. A pod is created with no memory request. What happens?",options:["Pod is rejected","Pod automatically gets request=256Mi","Pod runs without request","Validation error"],answer:1,explanation:"LimitRange injects default requests/limits into pods that don't specify them.\nThe pod gets the defaults automatically upon creation."},
    {q:"HPA scaled a Deployment to 8 replicas during peak load. Load dropped but replicas remain at 8. What is delaying scale-down?",options:["HPA doesn't support scale-down, only scale-up","stabilizationWindowSeconds (default 300s) prevents rapid scale-down to avoid flapping","metrics-server is not installed so HPA has no data","maxReplicas=8 also sets the effective minReplicas"],answer:1,explanation:"HPA includes a stabilization window for scale-down (default: 5 minutes).\nThis prevents rapid oscillations (flapping) between replica counts.\nCustomize via behavior.scaleDown.stabilizationWindowSeconds."},
    // ── Networking extra ──
    {q:"A pod tries to reach a ClusterIP Service and gets Connection refused. What do you check?",options:["DNS resolution - verify the Service name resolves correctly","kubectl get endpoints <service> - are there any addresses?","targetPort is wrong - Service points to a port the pod doesn't listen on","Pod is not Ready so it's not registered as an endpoint"],answer:1,explanation:"Connection refused on a ClusterIP usually means the Service has no Endpoints.\nCheck kubectl get endpoints - if empty, the selector doesn't match any Ready pods."},
    {q:"An Ingress returns 404 for all paths. Pods are up and the Service exists. What is the issue?",options:["TLS certificate is missing or invalid","IngressClass not set - the controller ignores the Ingress","Backend Service points to the wrong port","Ingress and Service are in different namespaces"],answer:1,explanation:"Since K8s 1.18, Ingress requires spec.ingressClassName.\nIf it's missing and the controller has no default IngressClass, the Ingress is ignored and all paths return 404."},
    {q:"A NetworkPolicy exists. Pod A can't reach Pod B in the same namespace. What do you check?",options:["Port number doesn't match between the pods","Both egress from A to B AND ingress to B from A must be explicitly allowed","CNI plugin doesn't support NetworkPolicy","Pods must be in the same namespace for NetworkPolicy to work"],answer:1,explanation:"NetworkPolicy is bidirectional.\nYou need: (1) egress from A to B allowed, (2) ingress to B from A allowed.\nThe CNI must support NetworkPolicy (Calico/Cilium yes, basic Flannel - no)."},
    {q:"Service selector: app=backend. The pod has label app=Backend (capital B). What happens?",options:["Service works anyway","Label selectors are case-sensitive - no match, no Endpoints","API error","Pod not created"],answer:1,explanation:"Label selectors are case-sensitive. app=backend ≠ app=Backend.\nThe Service won't point to any pod.\nDiagnose with: kubectl get endpoints <service>."},
    {q:"A pod can't resolve external DNS (example.com). CoreDNS is running. What do you check?",options:["CoreDNS logs and upstream resolver config","Ingress controller blocking outbound traffic","resolv.conf in the pod points to a wrong address","NetworkPolicy blocks egress to port 53"],answer:0,explanation:"CoreDNS resolves external names by forwarding to upstream resolvers.\nIf the upstream is misconfigured in the Corefile, external DNS fails.\nAlso check if a NetworkPolicy blocks outbound UDP 53."},
    {q:"How do you reach a NodePort Service (port 32000) from outside the cluster?",options:["http://service-name:32000","http://<any-node-IP>:32000","http://ClusterIP:32000","http://localhost:32000"],answer:1,explanation:"NodePort opens the port on every node.\nAccess from outside: http://<node-external-ip>:32000.\nFor production use LoadBalancer or Ingress instead."},
    {q:"A pod can't reach the internet. Internal DNS and ClusterIP work. What do you check?",options:["kube-proxy is not running on the node","Is NAT/masquerade configured? Does a NetworkPolicy block egress?","CoreDNS forward is not configured correctly","Firewall on the node blocks outbound traffic"],answer:1,explanation:"Internet access from a pod goes through NAT.\nCheck: (1) kube-proxy/CNI NAT rules, (2) NetworkPolicy egress not blocking 0.0.0.0/0, (3) Node firewall rules."},
    {q:"An Ingress has TLS configured. The browser shows a certificate error. The Secret exists. What do you check?",options:["Certificate has expired - check validity with openssl","Is the Secret in the same namespace as the Ingress? Does the CN/SAN match the domain?","Ingress Controller does not support TLS termination","TLS version is not supported by the browser"],answer:1,explanation:"A TLS Secret must be in the same namespace as the Ingress.\nThe certificate CN/SAN must match the domain.\nCheck: kubectl describe secret <tls-secret>."},
    {q:"A Service exists but kubectl get endpoints returns empty. What is the cause?",options:["Service and pods are in different namespaces","Pods are not Ready or selector doesn't match","Service type is ExternalName which doesn't create Endpoints","Service port doesn't match the targetPort"],answer:1,explanation:"Endpoints are created only when there are pods with matching labels that are also Ready.\nCheck: kubectl get pods --show-labels and compare with Service selector."},
    {q:"A Headless Service (clusterIP: None) - what does a DNS lookup on the Service name return?",options:["A single ClusterIP","A list of pod IPs directly","DNS error","Node IP"],answer:1,explanation:"A Headless Service has no ClusterIP.\nDNS returns A records for each pod directly.\nUseful for StatefulSets and direct peer-to-peer service discovery."},
    {q:"Two pods need to communicate. Which address is most reliable?",options:["Pod IP (changes on restart)","<service-name>.<namespace>.svc.cluster.local","Node hostname","External IP"],answer:1,explanation:"Always use Service DNS names, not pod IPs which change on every restart.\nFull DNS: <service>.<namespace>.svc.cluster.local.\nWithin the same namespace: just <service-name>."},
    // ── Config & Security extra ──
    {q:"A pod tries to read a Secret as an env var and gets 'secret not found'. What do you check?",options:["secretRef is wrong - Secret name doesn't match","Is the Secret in the same namespace as the pod?","Opaque Secret type is not supported as env var","Pod needs a ServiceAccount with Secret read permissions"],answer:1,explanation:"Secrets are namespace-scoped.\nA pod in namespace A cannot access a Secret in namespace B.\nCheck: kubectl get secret <name> -n <pod-namespace>."},
    {q:"kubectl get pods returns 'Error from server (Forbidden)'. What is the fix?",options:["Update kubeconfig with a new context","Define a RoleBinding linking the User/ServiceAccount to a Role with get/list pods","Switch to a namespace where the user has permissions","Add --as=admin flag to the command"],answer:1,explanation:"Forbidden = RBAC doesn't permit the action.\nYou need: a Role with resources:[\"pods\"], verbs:[\"get\",\"list\"], and a RoleBinding linking it to the user/serviceaccount."},
    {q:"A ConfigMap has keys key1 and key2. A pod tries to load key3. What happens?",options:["Pod runs with empty env var","Pod fails to start - 'key not found' error","ConfigMap updates automatically","Namespace mismatch"],answer:1,explanation:"Using valueFrom.configMapKeyRef with a missing key prevents the pod from starting, showing an Event error.\nVerify the key name in the ConfigMap."},
    {q:"An imagePullSecret is missing. The pod pulls from a private registry. What status?",options:["CrashLoopBackOff - container starts but crashes immediately","ImagePullBackOff - authentication fails against the registry","ContainerCreating - waiting for image download","ErrImagePull - image doesn't exist in registry"],answer:1,explanation:"Without imagePullSecret, kubelet can't authenticate to the private registry.\nPod shows ImagePullBackOff.\nFix: kubectl create secret docker-registry + add imagePullSecrets to pod spec."},
    {q:"A pod tries to run as root but PodSecurity standard=restricted. What happens?",options:["Pod runs as root","Pod is rejected - restricted requires runAsNonRoot:true","PodSecurity is inactive","Warning only"],answer:1,explanation:"PodSecurity Admission at restricted level requires runAsNonRoot:true, drop ALL capabilities, etc.\nPods that don't comply are rejected in Enforce mode."},
    {q:"A default-deny-all NetworkPolicy is applied to a namespace. What happens to traffic?",options:["Nothing changes - NetworkPolicy is only for monitoring","All ingress and egress is blocked unless explicitly allowed","Only DNS is blocked, other traffic continues","Only HTTP/HTTPS is blocked, direct TCP works"],answer:1,explanation:"A NetworkPolicy with empty podSelector:{} blocks all traffic.\nExplicit NetworkPolicies must be created for allowed traffic.\nNote: DNS (UDP 53) is also blocked!"},
    {q:"What is the difference between Role and ClusterRole in RBAC?",options:["No difference - both work across all namespaces","Role is namespace-scoped; ClusterRole applies to cluster-wide resources","ClusterRole is only for admin users; Role is for all users","Role is for pods only; ClusterRole is for nodes and pods"],answer:1,explanation:"Role: permissions in a specific namespace only.\nClusterRole: permissions for cluster-wide resources (Nodes, PVs, Namespaces) or any namespace via RoleBinding."},
    {q:"A Secret value is base64-encoded. What is a common encoding mistake?",options:["base64 is invalid in K8s","echo 'value' | base64 adds a trailing newline - use echo -n instead","Secret is double-encrypted","kubectl doesn't support base64"],answer:1,explanation:"echo 'value' | base64 appends a newline character.\nUse echo -n 'value' | base64 to avoid it.\nA Secret with a trailing newline causes the app to receive a value with an extra character."},
    {q:"A ServiceAccount's pod tries to read ConfigMaps but gets Forbidden. What is missing?",options:["ConfigMap needs a special annotation for ServiceAccount access","A Role with get/list ConfigMaps + RoleBinding to the ServiceAccount","ServiceAccount needs automountServiceAccountToken: true","Pod needs securityContext.allowPrivilegeEscalation"],answer:1,explanation:"RBAC permissions are granted to ServiceAccounts.\nYou need: a Role with resources:[\"configmaps\"], verbs:[\"get\",\"list\"], and a RoleBinding linking it to the pod's ServiceAccount."},
    {q:"A pod has securityContext.readOnlyRootFilesystem=true but writes to /tmp. What happens?",options:["Write succeeds","Write to /tmp fails unless /tmp is an emptyDir volume","Pod is rejected","Root filesystem is encrypted"],answer:1,explanation:"readOnlyRootFilesystem prevents writing anywhere in the container filesystem.\nFix: mount an emptyDir volume at /tmp to allow temporary writes without compromising security."},
    {q:"Are Kubernetes Secrets encrypted at rest by default?",options:["Yes, always encrypted in etcd by default","No - base64-encoded only; encryption requires EncryptionConfiguration","Secrets are not stored in etcd, only on kubelet","Secrets are encrypted if created with kubectl create secret"],answer:1,explanation:"By default, Secrets in etcd are base64-encoded, not encrypted.\nFor encryption at rest, configure EncryptionConfiguration on the API server.\nFor production: use Vault, AWS Secrets Manager, or External Secrets Operator."},
    // ── Storage extra ──
    {q:"A PVC is Pending. The StorageClass exists. What do you check?",options:["PVC size is too large - reduce the request","Is the provisioner running? Check PVC Events with kubectl describe pvc","accessMode is not supported by the StorageClass","PV in Released state blocks new binding"],answer:1,explanation:"PVC Pending with StorageClass = provisioner failed to create a PV. kubectl describe pvc shows Events.\nCheck: provisioner pod running? Correct permissions? Disk quota?"},
    {q:"A PV has Reclaim Policy=Retain. The PVC is deleted. What happens to the PV?",options:["PV is automatically deleted and releases the disk","PV stays in Released state - data preserved but no new PVC can bind to it","PV is wiped and becomes Available for reuse","PV automatically binds to the next PVC in the queue"],answer:1,explanation:"Retain: PV is not deleted or wiped.\nIt moves to Released.\nTo reuse: manually remove the claimRef.\nDelete policy: PV is deleted with the PVC.\nRecycle: deprecated."},
    {q:"A StorageClass doesn't exist. A PVC references it. What is the PVC status?",options:["PVC creates with default storage","PVC stays Pending with 'storageclass not found' event","PVC is deleted","PV is created"],answer:1,explanation:"If the StorageClass doesn't exist, the PVC stays Pending. kubectl describe pvc shows 'storageclass not found'.\nVerify the StorageClass name."},
    {q:"A pod gets Permission denied writing to a volume. Container UID is 1000. What do you check?",options:["initContainer that changes permissions on the volume","securityContext.fsGroup - sets volume ownership to a GID","runAsUser must be 0 (root) to write to the volume","PVC accessMode should be ReadWriteMany"],answer:1,explanation:"Pod securityContext.fsGroup sets the GID for files created in the volume.\nIf not set and the volume is owned by root, UID 1000 cannot write.\nSet fsGroup=1000 in the pod's securityContext."},
    {q:"A PVC has accessMode=ReadWriteOnce. Two pods try to mount it on different nodes. What happens?",options:["Both get access","The second pod stays Pending - RWO allows mount on only one node","DNS error","Eviction"],answer:1,explanation:"ReadWriteOnce: the volume can only be mounted ReadWrite on one node at a time.\nA second pod on a different node stays Pending.\nUse RWX (ReadWriteMany) for multi-node access."},
    {q:"How do you resize an existing PVC?",options:["You cannot resize a PVC - create a new one","StorageClass needs allowVolumeExpansion:true, then patch PVC with a larger size","Delete PVC and create with larger size without data loss","kubectl resize pvc with the new size"],answer:1,explanation:"To expand a PVC: (1) StorageClass.allowVolumeExpansion:true, (2) kubectl patch pvc with a larger size.\nOnline expansion is supported by most CSI drivers.\nShrinking is not supported."},
    {q:"A StatefulSet pod-0 is deleted and recreated. What happens to its PVC?",options:["PVC is deleted","PVC is retained - the new pod-0 attaches to the same PVC with the same data","A new PVC is created","Data is lost"],answer:1,explanation:"This is a core StatefulSet feature: PVCs are named deterministically and are never deleted when a pod is deleted.\nThe new pod reconnects to the same PVC with its data intact."},
    {q:"Dynamic provisioning is not working. kubectl describe pvc shows 'waiting for a volume to be created'. What is the cause?",options:["PVC accessMode not supported by the provisioner","Provisioner pod not running, wrong StorageClass provisioner, or quota reached","PV in Released state blocks provisioning","Node is not connected to the storage backend"],answer:1,explanation:"Dynamic provisioning requires: (1) StorageClass with a provisioner set, (2) Provisioner pod running, (3) RBAC for the provisioner, (4) cloud provider quota not exhausted."},
    {q:"A PV has capacity=10Gi. A PVC requests 5Gi. Will they bind?",options:["No - sizes must match exactly","Yes - a PV with larger capacity can satisfy a PVC with a smaller request","PVC receives 10Gi","PV shrinks to 5Gi"],answer:1,explanation:"K8s finds a PV that satisfies: matching accessMode, storageClass, and capacity >= requested.\nA 10Gi PV can satisfy a 5Gi PVC."},
    // ── Troubleshooting extra ──
    {q:"A node is NotReady. What is the first step?",options:["kubectl cordon node for preventive shutdown","kubectl describe node + ssh to node + systemctl status kubelet","kubectl drain node to move pods","Check kube-proxy logs on the node"],answer:1,explanation:"NotReady usually means kubelet isn't reporting.\nCheck: (1) kubectl describe node for Conditions, (2) ssh to node, (3) systemctl status kubelet, (4) journalctl -u kubelet -n 50."},
    {q:"kubectl exec -it pod -- /bin/bash returns 'OCI runtime exec failed'. Why?",options:["RBAC blocked - ServiceAccount lacks exec permission","bash is not in the image (distroless) - try /bin/sh","Container is not in Running state","exec is only possible with kubectl debug"],answer:1,explanation:"Minimal images like distroless don't include bash.\nTry: /bin/sh.\nIf that also fails: kubectl debug -it pod --image=busybox to attach an ephemeral debug container."},
    {q:"A pod has restartCount=47. What does this indicate?",options:["Healthy pod","Pod is crashing repeatedly - check logs --previous","Pod is upgrading","Normal behavior"],answer:1,explanation:"A high restartCount means the pod crashes and is restarted repeatedly (CrashLoopBackOff).\nCheck: kubectl logs <pod> --previous to see the last crash reason."},
    {q:"etcd has high disk I/O. The cluster is slow. What is the impact?",options:["Only new pods are affected, existing ones continue","API server slows down - etcd is the backend for all K8s objects; high latency slows the whole control plane","Scheduling is affected but API responses stay normal","kubelet heartbeats are affected and nodes appear NotReady"],answer:1,explanation:"etcd is the K8s brain.\nEvery kubectl apply/get goes through API server → etcd.\nDisk latency slows the entire control plane.\nFix: use SSDs, reduce watch connections, run etcd defrag."},
    {q:"kubectl get pods returns 'the server is currently unable to handle the request'. What is the cause?",options:["Pod crashed and caused a cascade failure","API server is rate-limiting or overloaded - too many requests","etcd is out of disk space","kubeconfig points to a wrong endpoint"],answer:1,explanation:"The API server limits requests to prevent overload.\nCommon causes: too many controllers, kubectl watch loops, or CI/CD running kubectl every second.\nCheck kube-apiserver metrics."},
    {q:"The container runtime (containerd) is unresponsive on a node. What doesn't work?",options:["Only new pods are affected, existing ones keep running normally","Container management is impossible - no exec, no new logs, no new pods","kubelet keeps running but can't report status","Node goes NotReady immediately and pods are evicted"],answer:1,explanation:"kubelet communicates with the runtime via CRI.\nWithout the runtime: no container start, no exec, no log streaming.\nExisting containers keep running in hardware but kubelet can't manage them."},
    {q:"CoreDNS pods have crashed. What is the symptom in the cluster?",options:["Nodes go NotReady because kubelet requires DNS","Internal DNS fails - pods can't resolve service names","Pod-to-pod communication stops completely","API server becomes unresponsive"],answer:1,explanation:"CoreDNS provides service discovery.\nWithout it, pods can't resolve <service>.<namespace>.svc.cluster.local and applications fail to connect to other services."},
    {q:"A cluster upgrade fails midway. What is the safest rollback approach?",options:["kubectl rollback","Restore etcd from a snapshot taken before the upgrade","Downgrade kubelet version on each node","Remove the control plane and reinstall"],answer:1,explanation:"The only reliable way to roll back a K8s cluster is to restore from an etcd snapshot.\nKubernetes does not support direct downgrades.\nAlways take an etcd snapshot before any upgrade."},
    {q:"After adding a new node to the cluster, kubectl get nodes shows it as Ready but pods are not scheduled on it. What do you check?",options:["Node lacks labels required by nodeSelector","The node has a NoSchedule taint. Check with kubectl describe node","Scheduler doesn't recognize the node yet","Node resources haven't been reported to the API server"],answer:1,explanation:"New nodes may arrive with a NoSchedule taint (e.g. node.kubernetes.io/not-ready).\nMost pods won't be scheduled on a tainted node without a matching toleration.\nCheck: kubectl describe node <name> | grep Taint."},
    {q:"A pod exited with code 1. What does this mean?",options:["Success","A general application error. The process reported a failure","SIGKILL from the kernel","Network issue"],answer:1,explanation:"Exit code 1 = generic error returned by the application.\nUnlike 137 (SIGKILL/OOM), here the app itself decided to exit with an error.\nCheck: kubectl logs <pod> --previous for the error details."},
    {q:"kubectl apply returns 'field is immutable'. What do you do?",options:["Add --force flag to kubectl apply","Delete and recreate the resource - immutable fields cannot be changed in place","kubectl replace --force allows changing immutable fields","kubectl patch with strategic merge bypasses immutability"],answer:1,explanation:"Some K8s fields are immutable after creation (e.g., spec.selector on Service/Deployment).\nTo change them you must: kubectl delete + kubectl apply with the new definition."},
    {q:"How do you verify all control plane components are healthy?",options:["kubectl get all","kubectl get componentstatuses and kubectl get --raw '/healthz'","docker ps","netstat"],answer:1,explanation:"kubectl get componentstatuses shows scheduler, controller-manager, etcd status.\nAlso check: kubectl get pods -n kube-system for all control plane pods.\nOn newer K8s: kubectl get --raw '/healthz?verbose'."},
    {q:"A pod has 2 containers. The first container crashes. What happens?",options:["Both containers restart together","Only the crashed container restarts, regardless of restartPolicy","The pod is deleted and recreated by the controller","Depends on restartPolicy - with Always only the crashed container restarts"],answer:3,explanation:"In a multi-container pod, each container is managed independently.\nA crashing container is restarted per the pod's restartPolicy (Always/OnFailure/Never).\nThe pod itself is not deleted and other containers keep running."},
    {q:"A Deployment rollout is paused (kubectl rollout pause). What happens to new kubectl apply changes?",options:["Changes are applied immediately","Changes are staged but not rolled out until kubectl rollout resume","Deployment is deleted","An error is returned"],answer:1,explanation:"A paused Deployment stages configuration changes but doesn't apply them to pods.\nThis lets you batch multiple changes.\nResume with: kubectl rollout resume deployment/<name>."},
    {q:"A pod has a preStop hook that takes 15 seconds. terminationGracePeriodSeconds is set to 10. What happens when the pod is deleted?",options:["preStop runs for the full 15 seconds","preStop is interrupted after 10 seconds and the container receives SIGKILL","Pod ignores the grace period for preStop hooks","Error. preStop cannot exceed the grace period"],answer:1,explanation:"The grace period covers both preStop hook execution and SIGTERM wait time.\nIf preStop exceeds the grace period, the container is killed.\nSet the grace period long enough to cover your preStop logic."},
    {q:"You want to run a one-off task in Kubernetes. Which resource is most appropriate?",options:["Deployment","Job - designed for run-to-completion workloads","DaemonSet","StatefulSet"],answer:1,explanation:"A Job runs pods until a specified number of successful completions.\nFor one-off tasks use a Job.\nFor scheduled tasks use CronJob.\nDeployments are for long-running services."},
    {q:"A pod's liveness probe keeps failing. What does Kubernetes do?",options:["Nothing","Restarts the container repeatedly","Deletes the pod permanently","Drains the node"],answer:1,explanation:"When a liveness probe fails, kubelet kills the container and restarts it (per restartPolicy).\nThis is intended for detecting and recovering from deadlocks.\nIf restartCount keeps rising, investigate the root cause."},
    {q:"What is the role of kube-scheduler in Kubernetes?",options:["Stores cluster state","Assigns pods to nodes based on resource availability and constraints","Runs containers","Manages Service networking"],answer:1,explanation:"kube-scheduler watches for unscheduled pods and selects the best node based on: resource requests, affinity/anti-affinity rules, taints/tolerations, and other constraints.\nIt only decides - kubelet does the actual work."},
  ],
};
